{"language": "plaintext", "code": "//+------------------------------------------------------------------+
//|                                                   CTR_EA_v1.mq5  |
//|                        Counter Trend Reclaim - Liquidity Sweep    |
//|                        Reversal EA for EUR/USD M5                 |
//+------------------------------------------------------------------+
#property copyright   "CTR EA v1.0"
#property version     "1.00"
#property description "Detects liquidity sweeps on fractal swing points and enters on reclaim."
#property description "Designed for EUR/USD M5 - NY Session (08:45 AM)"
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>
#include <Trade\AccountInfo.mqh>

//+------------------------------------------------------------------+
//| INPUT PARAMETERS                                                  |
//+------------------------------------------------------------------+
input group "══════ SESSION FILTER ══════"
input int      InpEntryHour       = 15;       // Entry hour (BROKER server time) — adjust to match 08:45 NY
input int      InpEntryMinute     = 45;       // Entry minute
input int      InpWindowBars      = 6;        // Signal window (# of M5 bars after entry time = 30 min)
input bool     InpMonday          = true;     // Trade Monday
input bool     InpTuesday         = true;     // Trade Tuesday
input bool     InpWednesday       = false;    // Trade Wednesday
input bool     InpThursday        = false;    // Trade Thursday
input bool     InpFriday          = true;     // Trade Friday

input group "══════ SWING DETECTION ══════"
input int      InpFractalBars     = 3;        // Fractal strength (bars left & right)
input int      InpSwingLookback   = 60;       // Max bars to scan for swing points

input group "══════ RISK MANAGEMENT ══════"
input double   InpSLPips          = 11.0;     // Stop Loss (pips)
input double   InpTPPips          = 29.0;     // Take Profit (pips)
input double   InpRiskPercent     = 1.0;      // Risk per trade (% of balance)
input double   InpFixedLots       = 0.0;      // Fixed lot size (0 = use risk %)

input group "══════ BREAK EVEN ══════"
input bool     InpUseBE           = true;     // Enable Break Even
input double   InpBETriggerPips   = 15.0;     // BE activation (pips in profit)
input double   InpBEOffsetPips    = 1.0;      // Lock-in above entry (pips)

input group "══════ TRAILING STOP ══════"
input bool     InpUseTrailing     = true;     // Enable Trailing Stop
input double   InpTrailStartPips  = 20.0;     // Trailing activation (pips in profit)
input double   InpTrailStepPips   = 3.0;      // Trailing step size (pips)

input group "══════ FILTERS ══════"
input double   InpMaxSpreadPts    = 25.0;     // Max spread (points) — skip if spread exceeds
input int      InpMaxTradesDay    = 1;        // Max trades per day

input group "══════ EA SETTINGS ══════"
input int      InpMagicNumber     = 202603;   // Magic Number
input string   InpComment         = "CTR";    // Order comment

//+------------------------------------------------------------------+
//| GLOBAL VARIABLES                                                  |
//+------------------------------------------------------------------+
CTrade         m_trade;
CPositionInfo  m_position;
CAccountInfo   m_account;

double         g_pipSize;          // value of 1 pip in price
int            g_pipMultiplier;    // 10 for 5-digit, 1 for 4-digit
datetime       g_lastBarTime;      // track new bars
bool           g_signalFiredToday; // one signal per day
int            g_tradesToday;      // daily trade counter
datetime       g_currentDay;       // track day change
bool           g_isPaused;         // manual pause state

// Dashboard
string         DP = "CTR_";       // dashboard prefix
int            g_dashX = 20;
int            g_dashY = 30;
int            g_dashW = 240;
int            g_dashH = 260;

//+------------------------------------------------------------------+
//| EXPERT INITIALIZATION                                             |
//+------------------------------------------------------------------+
int OnInit()
{
   //--- Validate timeframe
   if(_Period != PERIOD_M5)
   {
      Alert("CTR EA: Designed for M5 timeframe. Current: ", EnumToString(_Period));
      // Allow but warn — don't block
   }

   //--- Configure trade object
   m_trade.SetExpertMagicNumber(InpMagicNumber);
   m_trade.SetDeviationInPoints(15);
   m_trade.SetTypeFilling(ORDER_FILLING_IOC);

   //--- Calculate pip size based on digit count
   int digits = (int)SymbolInfoInteger(_Symbol, SYMBOL_DIGITS);
   if(digits == 3 || digits == 5)
   {
      g_pipSize       = _Point * 10.0;
      g_pipMultiplier = 10;
   }
   else
   {
      g_pipSize       = _Point;
      g_pipMultiplier = 1;
   }

   //--- Initialize state
   g_lastBarTime      = 0;
   g_signalFiredToday = false;
   g_tradesToday      = 0;
   g_currentDay       = 0;
   g_isPaused         = false;

   //--- Create dashboard
   CreateDashboard();
   UpdateDashboard();

   Print("═══════════════════════════════════════════");
   Print("  CTR EA v1.0 initialized on ", _Symbol);
   Print("  Pip size: ", DoubleToString(g_pipSize, digits));
   Print("  Entry window: ", IntegerToString(InpEntryHour), ":",
         (InpEntryMinute < 10 ? "0" : ""), IntegerToString(InpEntryMinute),
         " (server time) + ", IntegerToString(InpWindowBars * 5), " min");
   Print("═══════════════════════════════════════════");

   return(INIT_SUCCEEDED);
}

//+------------------------------------------------------------------+
//| EXPERT DEINITIALIZATION                                           |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   DeleteDashboard();
   Comment("");
}

//+------------------------------------------------------------------+
//| EXPERT TICK FUNCTION                                              |
//+------------------------------------------------------------------+
void OnTick()
{
   //--- Update dashboard every tick (spread, P/L)
   UpdateDashboard();

   //--- Manage open positions (BE / Trailing) every tick
   ManageOpenPositions();

   //--- New bar check — signal logic runs once per bar
   if(!IsNewBar())
      return;

   //--- Daily reset
   ResetDailyCounters();

   //--- Count today's trades
   g_tradesToday = CountTradesToday();

   //--- If paused, skip signal logic
   if(g_isPaused)
      return;

   //--- Check day filter
   if(!IsTradeDay())
      return;

   //--- Check if within signal window
   if(!IsInSignalWindow())
      return;

   //--- Check daily trade limit
   if(g_tradesToday >= InpMaxTradesDay)
      return;

   //--- Check if signal already fired today
   if(g_signalFiredToday)
      return;

   //--- Spread filter
   double spread = SymbolInfoInteger(_Symbol, SYMBOL_SPREAD);
   if(spread > InpMaxSpreadPts)
   {
      Print("CTR: Spread too high (", spread, " > ", InpMaxSpreadPts, "). Skipping.");
      return;
   }

   //--- No open positions from this EA allowed (one at a time)
   if(HasOpenPosition())
      return;

   //--- CORE LOGIC: Detect liquidity sweep on last closed bar
   double swingHigh = 0, swingLow = 0;
   bool foundHigh = FindNearestSwingHigh(swingHigh);
   bool foundLow  = FindNearestSwingLow(swingLow);

   //--- Get last closed bar data (bar index 1)
   double barHigh  = iHigh(_Symbol, _Period, 1);
   double barLow   = iLow(_Symbol, _Period, 1);
   double barClose = iClose(_Symbol, _Period, 1);
   double barOpen  = iOpen(_Symbol, _Period, 1);

   //--- BULLISH SWEEP: Low broken + close above swing low level
   if(foundLow && barLow < swingLow && barClose > swingLow)
   {
      double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
      double sl  = ask - InpSLPips * g_pipSize;
      double tp  = ask + InpTPPips * g_pipSize;
      double lots = CalculateLotSize();

      if(lots > 0)
      {
         // Normalize prices
         sl = NormalizeDouble(sl, _Digits);
         tp = NormalizeDouble(tp, _Digits);

         if(m_trade.Buy(lots, _Symbol, ask, sl, tp, InpComment + " BUY"))
         {
            Print("CTR BUY: Sweep low=", DoubleToString(swingLow, _Digits),
                  " | Bar low=", DoubleToString(barLow, _Digits),
                  " | Close=", DoubleToString(barClose, _Digits),
                  " | Lots=", DoubleToString(lots, 2));
            g_signalFiredToday = true;
         }
         else
         {
            Print("CTR BUY FAILED: ", m_trade.ResultRetcodeDescription());
         }
      }
      return;
   }

   //--- BEARISH SWEEP: High broken + close below swing high level
   if(foundHigh && barHigh > swingHigh && barClose < swingHigh)
   {
      double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
      double sl  = bid + InpSLPips * g_pipSize;
      double tp  = bid - InpTPPips * g_pipSize;
      double lots = CalculateLotSize();

      if(lots > 0)
      {
         sl = NormalizeDouble(sl, _Digits);
         tp = NormalizeDouble(tp, _Digits);

         if(m_trade.Sell(lots, _Symbol, bid, sl, tp, InpComment + " SELL"))
         {
            Print("CTR SELL: Sweep high=", DoubleToString(swingHigh, _Digits),
                  " | Bar high=", DoubleToString(barHigh, _Digits),
                  " | Close=", DoubleToString(barClose, _Digits),
                  " | Lots=", DoubleToString(lots, 2));
            g_signalFiredToday = true;
         }
         else
         {
            Print("CTR SELL FAILED: ", m_trade.ResultRetcodeDescription());
         }
      }
      return;
   }
}

//+------------------------------------------------------------------+
//| CHART EVENT — Dashboard button clicks                             |
//+------------------------------------------------------------------+
void OnChartEvent(const int id, const long &lparam, const double &dparam, const string &sparam)
{
   if(id == CHARTEVENT_OBJECT_CLICK)
   {
      //--- Close All button
      if(sparam == DP + "BtnCloseAll")
      {
         CloseAllPositions();
         ObjectSetInteger(0, DP + "BtnCloseAll", OBJPROP_STATE, false);
      }
      //--- Close Winners button
      else if(sparam == DP + "BtnCloseWin")
      {
         CloseWinningPositions();
         ObjectSetInteger(0, DP + "BtnCloseWin", OBJPROP_STATE, false);
      }
      //--- Pause / Resume button
      else if(sparam == DP + "BtnPause")
      {
         g_isPaused = !g_isPaused;
         ObjectSetString(0, DP + "BtnPause", OBJPROP_TEXT, g_isPaused ? "▶ Resume" : "⏸ Pause");
         ObjectSetInteger(0, DP + "BtnPause", OBJPROP_STATE, false);
         Print("CTR EA: ", g_isPaused ? "PAUSED" : "RESUMED");
         UpdateDashboard();
      }
   }
}

//+------------------------------------------------------------------+
//| SWING DETECTION — Fractal-based                                   |
//+------------------------------------------------------------------+
bool FindNearestSwingHigh(double &level)
{
   int n = InpFractalBars;
   // Most recent confirmable fractal starts at bar n+1
   int startBar = n + 1;
   int endBar   = MathMin(startBar + InpSwingLookback, Bars(_Symbol, _Period) - n - 1);

   for(int i = startBar; i <= endBar; i++)
   {
      double hi = iHigh(_Symbol, _Period, i);
      bool isFractal = true;

      // Check N bars to the left (older = higher index)
      for(int j = 1; j <= n; j++)
      {
         if(iHigh(_Symbol, _Period, i + j) >= hi)
         {
            isFractal = false;
            break;
         }
      }
      if(!isFractal) continue;

      // Check N bars to the right (newer = lower index)
      for(int j = 1; j <= n; j++)
      {
         if(iHigh(_Symbol, _Period, i - j) >= hi)
         {
            isFractal = false;
            break;
         }
      }

      if(isFractal)
      {
         level = hi;
         return true;
      }
   }
   return false;
}

//+------------------------------------------------------------------+
bool FindNearestSwingLow(double &level)
{
   int n = InpFractalBars;
   int startBar = n + 1;
   int endBar   = MathMin(startBar + InpSwingLookback, Bars(_Symbol, _Period) - n - 1);

   for(int i = startBar; i <= endBar; i++)
   {
      double lo = iLow(_Symbol, _Period, i);
      bool isFractal = true;

      // Left side (older bars)
      for(int j = 1; j <= n; j++)
      {
         if(iLow(_Symbol, _Period, i + j) <= lo)
         {
            isFractal = false;
            break;
         }
      }
      if(!isFractal) continue;

      // Right side (newer bars)
      for(int j = 1; j <= n; j++)
      {
         if(iLow(_Symbol, _Period, i - j) <= lo)
         {
            isFractal = false;
            break;
         }
      }

      if(isFractal)
      {
         level = lo;
         return true;
      }
   }
   return false;
}

//+------------------------------------------------------------------+
//| LOT SIZE CALCULATION                                              |
//+------------------------------------------------------------------+
double CalculateLotSize()
{
   //--- Fixed lot override
   if(InpFixedLots > 0)
   {
      return NormalizeLots(InpFixedLots);
   }

   //--- Risk-based calculation
   double balance    = m_account.Balance();
   double riskAmount = balance * InpRiskPercent / 100.0;

   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickValue <= 0 || tickSize <= 0)
   {
      Print("CTR: Invalid tick value/size. Using minimum lot.");
      return SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   }

   double slDistance  = InpSLPips * g_pipSize;
   double lossPerLot = (slDistance / tickSize) * tickValue;

   if(lossPerLot <= 0)
   {
      Print("CTR: Loss per lot calculation error.");
      return SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   }

   double lots = riskAmount / lossPerLot;
   return NormalizeLots(lots);
}

//+------------------------------------------------------------------+
double NormalizeLots(double lots)
{
   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   if(lotStep <= 0) lotStep = 0.01;

   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lots, minLot);
   lots = MathMin(lots, maxLot);

   return NormalizeDouble(lots, 2);
}

//+------------------------------------------------------------------+
//| TRADE MANAGEMENT — Break Even & Trailing Stop                     |
//+------------------------------------------------------------------+
void ManageOpenPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_position.SelectByIndex(i))
         continue;

      if(m_position.Magic() != InpMagicNumber)
         continue;

      if(m_position.Symbol() != _Symbol)
         continue;

      double openPrice = m_position.PriceOpen();
      double currentSL = m_position.StopLoss();
      double currentTP = m_position.PriceCurrent();
      ulong  ticket    = m_position.Ticket();

      if(m_position.PositionType() == POSITION_TYPE_BUY)
      {
         double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
         double profitPips = (bid - openPrice) / g_pipSize;

         //--- Break Even
         if(InpUseBE && profitPips >= InpBETriggerPips)
         {
            double newSL = NormalizeDouble(openPrice + InpBEOffsetPips * g_pipSize, _Digits);
            if(currentSL < newSL)
            {
               m_trade.PositionModify(ticket, newSL, m_position.TakeProfit());
            }
         }

         //--- Trailing Stop
         if(InpUseTrailing && profitPips >= InpTrailStartPips)
         {
            double trailSL = NormalizeDouble(bid - InpTrailStepPips * g_pipSize, _Digits);
            if(trailSL > currentSL)
            {
               m_trade.PositionModify(ticket, trailSL, m_position.TakeProfit());
            }
         }
      }
      else if(m_position.PositionType() == POSITION_TYPE_SELL)
      {
         double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
         double profitPips = (openPrice - ask) / g_pipSize;

         //--- Break Even
         if(InpUseBE && profitPips >= InpBETriggerPips)
         {
            double newSL = NormalizeDouble(openPrice - InpBEOffsetPips * g_pipSize, _Digits);
            if(currentSL > newSL || currentSL == 0)
            {
               m_trade.PositionModify(ticket, newSL, m_position.TakeProfit());
            }
         }

         //--- Trailing Stop
         if(InpUseTrailing && profitPips >= InpTrailStartPips)
         {
            double trailSL = NormalizeDouble(ask + InpTrailStepPips * g_pipSize, _Digits);
            if(trailSL < currentSL || currentSL == 0)
            {
               m_trade.PositionModify(ticket, trailSL, m_position.TakeProfit());
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| SESSION & TIME FILTERS                                            |
//+------------------------------------------------------------------+
bool IsNewBar()
{
   datetime barTime = iTime(_Symbol, _Period, 0);
   if(barTime == g_lastBarTime)
      return false;

   g_lastBarTime = barTime;
   return true;
}

//+------------------------------------------------------------------+
void ResetDailyCounters()
{
   MqlDateTime dt;
   TimeCurrent(dt);
   datetime today = StringToTime(IntegerToString(dt.year) + "." +
                                  IntegerToString(dt.mon) + "." +
                                  IntegerToString(dt.day));

   if(today != g_currentDay)
   {
      g_currentDay       = today;
      g_signalFiredToday = false;
      g_tradesToday      = 0;
   }
}

//+------------------------------------------------------------------+
bool IsTradeDay()
{
   MqlDateTime dt;
   TimeCurrent(dt);

   switch(dt.day_of_week)
   {
      case 1: return InpMonday;
      case 2: return InpTuesday;
      case 3: return InpWednesday;
      case 4: return InpThursday;
      case 5: return InpFriday;
      default: return false; // Sat/Sun
   }
}

//+------------------------------------------------------------------+
bool IsInSignalWindow()
{
   MqlDateTime dt;
   TimeCurrent(dt);

   // Convert entry time to minutes since midnight
   int entryMinutes  = InpEntryHour * 60 + InpEntryMinute;
   int windowEnd     = entryMinutes + InpWindowBars * 5; // each bar = 5 min on M5
   int currentMinutes = dt.hour * 60 + dt.min;

   return (currentMinutes >= entryMinutes && currentMinutes < windowEnd);
}

//+------------------------------------------------------------------+
//| POSITION HELPERS                                                  |
//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_position.SelectByIndex(i))
         continue;
      if(m_position.Magic() == InpMagicNumber && m_position.Symbol() == _Symbol)
         return true;
   }
   return false;
}

//+------------------------------------------------------------------+
int CountTradesToday()
{
   int count = 0;
   datetime startOfDay = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));

   //--- Count open positions from today
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_position.SelectByIndex(i))
         continue;
      if(m_position.Magic() == InpMagicNumber && m_position.Symbol() == _Symbol)
      {
         if(m_position.Time() >= startOfDay)
            count++;
      }
   }

   //--- Count closed trades from today via deal history
   datetime endOfDay = startOfDay + 86400;
   HistorySelect(startOfDay, endOfDay);

   for(int i = HistoryDealsTotal() - 1; i >= 0; i--)
   {
      ulong dealTicket = HistoryDealGetTicket(i);
      if(dealTicket == 0) continue;

      if(HistoryDealGetInteger(dealTicket, DEAL_MAGIC) == InpMagicNumber &&
         HistoryDealGetString(dealTicket, DEAL_SYMBOL) == _Symbol &&
         HistoryDealGetInteger(dealTicket, DEAL_ENTRY) == DEAL_ENTRY_IN)
      {
         count++;
      }
   }

   return count;
}

//+------------------------------------------------------------------+
double GetDailyPnL()
{
   double pnl = 0;
   datetime startOfDay = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));
   datetime endOfDay   = startOfDay + 86400;

   //--- Closed deals profit
   HistorySelect(startOfDay, endOfDay);
   for(int i = HistoryDealsTotal() - 1; i >= 0; i--)
   {
      ulong dealTicket = HistoryDealGetTicket(i);
      if(dealTicket == 0) continue;

      if(HistoryDealGetInteger(dealTicket, DEAL_MAGIC) == InpMagicNumber &&
         HistoryDealGetString(dealTicket, DEAL_SYMBOL) == _Symbol &&
         HistoryDealGetInteger(dealTicket, DEAL_ENTRY) == DEAL_ENTRY_OUT)
      {
         pnl += HistoryDealGetDouble(dealTicket, DEAL_PROFIT)
              + HistoryDealGetDouble(dealTicket, DEAL_SWAP)
              + HistoryDealGetDouble(dealTicket, DEAL_COMMISSION);
      }
   }

   //--- Add floating P/L from open positions
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_position.SelectByIndex(i))
         continue;
      if(m_position.Magic() == InpMagicNumber && m_position.Symbol() == _Symbol)
      {
         pnl += m_position.Profit() + m_position.Swap() + m_position.Commission();
      }
   }

   return pnl;
}

//+------------------------------------------------------------------+
//| CLOSE HELPERS                                                     |
//+------------------------------------------------------------------+
void CloseAllPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_position.SelectByIndex(i))
         continue;
      if(m_position.Magic() == InpMagicNumber && m_position.Symbol() == _Symbol)
      {
         m_trade.PositionClose(m_position.Ticket());
      }
   }
   Print("CTR: All positions closed.");
}

//+------------------------------------------------------------------+
void CloseWinningPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_position.SelectByIndex(i))
         continue;
      if(m_position.Magic() == InpMagicNumber && m_position.Symbol() == _Symbol)
      {
         if(m_position.Profit() > 0)
         {
            m_trade.PositionClose(m_position.Ticket());
         }
      }
   }
   Print("CTR: Winning positions closed.");
}

//+------------------------------------------------------------------+
//| DASHBOARD — Create / Update / Delete                              |
//+------------------------------------------------------------------+
void CreateDashboard()
{
   //--- Background panel
   CreateRectLabel(DP + "BG", g_dashX, g_dashY, g_dashW, g_dashH,
