//+------------------------------------------------------------------+
//|                                               CTR_Reclaim_v1.mq5 |
//|        Counter Trend Reclaim — Liquidity Sweep Reversal EA       |
//|        Reverse-engineered from CTR Reclaim .set files & video    |
//+------------------------------------------------------------------+
#property copyright   "CTR Reclaim v1.1"
#property version     "1.10"
#property description "Detects liquidity sweeps on recent swing points"
#property description "and enters on price reclaim (close back inside range)."
#property description "Optimized for EUR/USD & XAUUSD on M10."
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>
#include <Trade\AccountInfo.mqh>

//+------------------------------------------------------------------+
//| ENUMS                                                             |
//+------------------------------------------------------------------+
enum ENUM_TRADE_TYPE
{
   Both  = 0,  // Both (Buy & Sell)
   Buy   = 1,  // Buy only
   Sell  = 2   // Sell only
};

//+------------------------------------------------------------------+
//| INPUT PARAMETERS — matching original CTR Reclaim structure        |
//+------------------------------------------------------------------+
input group "══════ GENERAL SETTINGS ══════"
input int              MagicNumber       = 1010;        // Magic Number
input double           RiskPercent       = 0.25;        // Risk per trade (% of balance)
input int              SL_ticks          = 90;          // Stop Loss (ticks/points)
input int              TP_ticks          = 180;         // Take Profit (ticks/points)
input int              MaxTradesPerDay   = 1;           // Max trades per day
input int              MaxSpreadPoints   = 30;          // Max spread (points)
input int              SlippagePoints    = 10;          // Max slippage (points)
input ENUM_TRADE_TYPE  TradeType         = Both;        // Trade direction

input group "══════ DAY FILTER ══════"
input bool             TradeSunday       = false;       // Trade Sunday
input bool             TradeMonday       = false;       // Trade Monday
input bool             TradeTuesday      = true;        // Trade Tuesday
input bool             TradeWednesday    = true;        // Trade Wednesday
input bool             TradeThursday     = true;        // Trade Thursday
input bool             TradeFriday       = true;        // Trade Friday
input bool             TradeSaturday     = false;       // Trade Saturday

input group "══════ SESSION WINDOW (broker server time) ══════"
input int              StartHour         = 13;          // Window start hour
input int              StartMin          = 50;          // Window start minute
input int              EndHour           = 13;          // Window end hour
input int              EndMin            = 50;          // Window end minute

input group "══════ SWING DETECTION ══════"
input int              SwingLookback     = 30;          // Bars to scan for swing H/L
input int              FractalBars       = 3;           // Fractal strength (bars each side)

input group "══════ BREAK EVEN (optional) ══════"
input bool             EnableBreakeven   = false;       // Enable Break Even
input int              BE_TriggerTicks   = 100;         // BE activation distance (ticks)
input int              BE_OffsetTicks    = 10;          // Lock-in above entry (ticks)

input group "══════ PARTIALS (optional) ══════"
input bool             EnablePartials    = false;       // Enable partial close
input double           PartialPercent    = 50.0;        // % of position to close
input int              PartialTrigTicks  = 120;         // Partial trigger distance (ticks)

input group "══════ DISPLAY ══════"
input bool             ShowChartComment  = true;        // Show info panel on chart

//+------------------------------------------------------------------+
//| GLOBAL VARIABLES                                                  |
//+------------------------------------------------------------------+
CTrade         m_trade;
CPositionInfo  m_pos;
CAccountInfo   m_account;

datetime       g_lastBarTime;
datetime       g_currentDay;
bool           g_signalFiredToday;
int            g_tradesToday;
bool           g_partialDone;         // track if partial close already done

// Dashboard object prefix
string         DP = "CTR_";
int            g_dashX = 20, g_dashY = 30;

//+------------------------------------------------------------------+
//| EXPERT INITIALIZATION                                             |
//+------------------------------------------------------------------+
int OnInit()
{
   // Configure trade object
   m_trade.SetExpertMagicNumber(MagicNumber);
   m_trade.SetDeviationInPoints(SlippagePoints);
   m_trade.SetTypeFilling(ORDER_FILLING_IOC);

   // Initialize state
   g_lastBarTime      = 0;
   g_currentDay       = 0;
   g_signalFiredToday = false;
   g_tradesToday      = 0;
   g_partialDone      = false;

   // Build dashboard
   if(ShowChartComment)
      CreateDashboard();

   // Log startup
   Print("═══════════════════════════════════════════════════════");
   Print("  CTR Reclaim v1.1 initialized");
   Print("  Symbol: ", _Symbol, " | TF: ", EnumToString(_Period));
   Print("  SL: ", SL_ticks, " ticks | TP: ", TP_ticks, " ticks");
   Print("  Window: ", IntegerToString(StartHour), ":",
         StringFormat("%02d", StartMin), " — ",
         IntegerToString(EndHour), ":", StringFormat("%02d", EndMin));
   Print("  Risk: ", DoubleToString(RiskPercent, 2), "%");
   Print("═══════════════════════════════════════════════════════");

   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
//| EXPERT DEINITIALIZATION                                           |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   ObjectsDeleteAll(0, DP);
   Comment("");
}

//+------------------------------------------------------------------+
//| EXPERT TICK FUNCTION                                              |
//+------------------------------------------------------------------+
void OnTick()
{
   // Update dashboard every tick
   if(ShowChartComment)
      UpdateDashboard();

   // Manage open positions (BE / Partials) every tick
   ManageOpenPositions();

   // Signal logic only on new bar
   if(!IsNewBar())
      return;

   // Daily reset
   CheckDayReset();

   // Update trade counter
   g_tradesToday = CountTradesToday();

   // ── FILTERS ──
   if(!IsTradingDay())         return;
   if(!IsInSessionWindow())    return;
   if(g_signalFiredToday)      return;
   if(g_tradesToday >= MaxTradesPerDay) return;
   if(HasOpenPosition())       return;

   // Spread check
   long spread = SymbolInfoInteger(_Symbol, SYMBOL_SPREAD);
   if(spread > MaxSpreadPoints)
   {
      Print("CTR: Spread ", spread, " > max ", MaxSpreadPoints, ". Skip.");
      return;
   }

   // ── CORE: Find swings and check for sweep ──
   double swingHigh = 0, swingLow = 0;
   bool hasSwingH = FindNearestSwingHigh(swingHigh);
   bool hasSwingL = FindNearestSwingLow(swingLow);

   // Last closed bar (index 1)
   double bHigh  = iHigh(_Symbol, _Period, 1);
   double bLow   = iLow(_Symbol, _Period, 1);
   double bClose = iClose(_Symbol, _Period, 1);
   double bOpen  = iOpen(_Symbol, _Period, 1);

   // ── BULLISH SWEEP: price swept below swing low, closed back above ──
   if(hasSwingL && (TradeType == Both || TradeType == Buy))
   {
      if(bLow < swingLow && bClose > swingLow)
      {
         ExecuteBuy(swingLow, bLow, bClose);
         return;
      }
   }

   // ── BEARISH SWEEP: price swept above swing high, closed back below ──
   if(hasSwingH && (TradeType == Both || TradeType == Sell))
   {
      if(bHigh > swingHigh && bClose < swingHigh)
      {
         ExecuteSell(swingHigh, bHigh, bClose);
         return;
      }
   }
}

//+------------------------------------------------------------------+
//| CHART EVENT — Button clicks                                       |
//+------------------------------------------------------------------+
void OnChartEvent(const int id, const long &lparam,
                  const double &dparam, const string &sparam)
{
   if(id != CHARTEVENT_OBJECT_CLICK)
      return;

   if(sparam == DP + "BtnCloseAll")
   {
      CloseAllPositions();
      ObjectSetInteger(0, sparam, OBJPROP_STATE, false);
   }
   else if(sparam == DP + "BtnCloseWin")
   {
      CloseWinningPositions();
      ObjectSetInteger(0, sparam, OBJPROP_STATE, false);
   }
   else if(sparam == DP + "BtnPause")
   {
      g_signalFiredToday = !g_signalFiredToday; // toggle pause
      ObjectSetInteger(0, sparam, OBJPROP_STATE, false);
   }
}

//+------------------------------------------------------------------+
//| TRADE EXECUTION                                                   |
//+------------------------------------------------------------------+
void ExecuteBuy(double swingLevel, double barLow, double barClose)
{
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double sl  = NormalizeDouble(ask - SL_ticks * _Point, _Digits);
   double tp  = NormalizeDouble(ask + TP_ticks * _Point, _Digits);
   double lots = CalculateLotSize();

   if(lots <= 0) return;

   if(m_trade.Buy(lots, _Symbol, ask, sl, tp, "CTR BUY"))
   {
      g_signalFiredToday = true;
      g_partialDone      = false;
      Print("✓ CTR BUY | Sweep low=", DoubleToString(swingLevel, _Digits),
            " | Bar low=", DoubleToString(barLow, _Digits),
            " | Close=", DoubleToString(barClose, _Digits),
            " | Lots=", DoubleToString(lots, 2),
            " | SL=", DoubleToString(sl, _Digits),
            " | TP=", DoubleToString(tp, _Digits));
   }
   else
   {
      Print("✗ CTR BUY FAILED: ", m_trade.ResultRetcodeDescription());
   }
}

//+------------------------------------------------------------------+
void ExecuteSell(double swingLevel, double barHigh, double barClose)
{
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double sl  = NormalizeDouble(bid + SL_ticks * _Point, _Digits);
   double tp  = NormalizeDouble(bid - TP_ticks * _Point, _Digits);
   double lots = CalculateLotSize();

   if(lots <= 0) return;

   if(m_trade.Sell(lots, _Symbol, bid, sl, tp, "CTR SELL"))
   {
      g_signalFiredToday = true;
      g_partialDone      = false;
      Print("✓ CTR SELL | Sweep high=", DoubleToString(swingLevel, _Digits),
            " | Bar high=", DoubleToString(barHigh, _Digits),
            " | Close=", DoubleToString(barClose, _Digits),
            " | Lots=", DoubleToString(lots, 2),
            " | SL=", DoubleToString(sl, _Digits),
            " | TP=", DoubleToString(tp, _Digits));
   }
   else
   {
      Print("✗ CTR SELL FAILED: ", m_trade.ResultRetcodeDescription());
   }
}

//+------------------------------------------------------------------+
//| SWING DETECTION — Fractal-based                                   |
//+------------------------------------------------------------------+
bool FindNearestSwingHigh(double &level)
{
   int n = FractalBars;
   int startBar = n + 1;  // first confirmable fractal
   int maxBar = MathMin(startBar + SwingLookback, Bars(_Symbol, _Period) - n - 1);

   for(int i = startBar; i <= maxBar; i++)
   {
      double hi = iHigh(_Symbol, _Period, i);
      bool valid = true;

      // Left side (older bars)
      for(int j = 1; j <= n; j++)
      {
         if(iHigh(_Symbol, _Period, i + j) >= hi)
         { valid = false; break; }
      }
      if(!valid) continue;

      // Right side (newer bars)
      for(int j = 1; j <= n; j++)
      {
         if(iHigh(_Symbol, _Period, i - j) >= hi)
         { valid = false; break; }
      }

      if(valid)
      {
         level = hi;
         return true;
      }
   }
   return false;
}

//+------------------------------------------------------------------+
bool FindNearestSwingLow(double &level)
{
   int n = FractalBars;
   int startBar = n + 1;
   int maxBar = MathMin(startBar + SwingLookback, Bars(_Symbol, _Period) - n - 1);

   for(int i = startBar; i <= maxBar; i++)
   {
      double lo = iLow(_Symbol, _Period, i);
      bool valid = true;

      for(int j = 1; j <= n; j++)
      {
         if(iLow(_Symbol, _Period, i + j) <= lo)
         { valid = false; break; }
      }
      if(!valid) continue;

      for(int j = 1; j <= n; j++)
      {
         if(iLow(_Symbol, _Period, i - j) <= lo)
         { valid = false; break; }
      }

      if(valid)
      {
         level = lo;
         return true;
      }
   }
   return false;
}

//+------------------------------------------------------------------+
//| LOT SIZE CALCULATION                                              |
//+------------------------------------------------------------------+
double CalculateLotSize()
{
   double balance    = m_account.Balance();
   double riskAmount = balance * RiskPercent / 100.0;

   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickValue <= 0 || tickSize <= 0)
   {
      Print("CTR: Invalid tick value/size. Using min lot.");
      return SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   }

   // SL distance in price terms
   double slPrice    = SL_ticks * _Point;
   double lossPerLot = (slPrice / tickSize) * tickValue;

   if(lossPerLot <= 0)
   {
      Print("CTR: Loss per lot = 0. Using min lot.");
      return SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   }

   double lots = riskAmount / lossPerLot;
   return NormalizeLots(lots);
}

//+------------------------------------------------------------------+
double NormalizeLots(double lots)
{
   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);

   if(lotStep <= 0) lotStep = 0.01;

   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lots, minLot);
   lots = MathMin(lots, maxLot);

   return NormalizeDouble(lots, 2);
}

//+------------------------------------------------------------------+
//| POSITION MANAGEMENT — Break Even & Partial Close                  |
//+------------------------------------------------------------------+
void ManageOpenPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i))                   continue;
      if(m_pos.Magic() != MagicNumber)               continue;
      if(m_pos.Symbol() != _Symbol)                  continue;

      double openPrice = m_pos.PriceOpen();
      double curSL     = m_pos.StopLoss();
      double curTP     = m_pos.TakeProfit();
      ulong  ticket    = m_pos.Ticket();

      //=== BUY position ===
      if(m_pos.PositionType() == POSITION_TYPE_BUY)
      {
         double bid        = SymbolInfoDouble(_Symbol, SYMBOL_BID);
         double profitTicks = (bid - openPrice) / _Point;

         // Break Even
         if(EnableBreakeven && profitTicks >= BE_TriggerTicks)
         {
            double newSL = NormalizeDouble(openPrice + BE_OffsetTicks * _Point, _Digits);
            if(curSL < newSL)
               m_trade.PositionModify(ticket, newSL, curTP);
         }

         // Partial Close
         if(EnablePartials && !g_partialDone && profitTicks >= PartialTrigTicks)
         {
            double closeLots = NormalizeLots(m_pos.Volume() * PartialPercent / 100.0);
            if(closeLots > 0 && closeLots < m_pos.Volume())
            {
               m_trade.PositionClosePartial(ticket, closeLots);
               g_partialDone = true;
               Print("CTR: Partial close BUY ", DoubleToString(closeLots, 2), " lots");
            }
         }
      }
      //=== SELL position ===
      else if(m_pos.PositionType() == POSITION_TYPE_SELL)
      {
         double ask        = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
         double profitTicks = (openPrice - ask) / _Point;

         // Break Even
         if(EnableBreakeven && profitTicks >= BE_TriggerTicks)
         {
            double newSL = NormalizeDouble(openPrice - BE_OffsetTicks * _Point, _Digits);
            if(curSL > newSL || curSL == 0)
               m_trade.PositionModify(ticket, newSL, curTP);
         }

         // Partial Close
         if(EnablePartials && !g_partialDone && profitTicks >= PartialTrigTicks)
         {
            double closeLots = NormalizeLots(m_pos.Volume() * PartialPercent / 100.0);
            if(closeLots > 0 && closeLots < m_pos.Volume())
            {
               m_trade.PositionClosePartial(ticket, closeLots);
               g_partialDone = true;
               Print("CTR: Partial close SELL ", DoubleToString(closeLots, 2), " lots");
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| TIME & SESSION FILTERS                                            |
//+------------------------------------------------------------------+
bool IsNewBar()
{
   datetime t = iTime(_Symbol, _Period, 0);
   if(t == g_lastBarTime) return false;
   g_lastBarTime = t;
   return true;
}

//+------------------------------------------------------------------+
void CheckDayReset()
{
   MqlDateTime dt;
   TimeCurrent(dt);
   datetime today = StringToTime(StringFormat("%d.%02d.%02d", dt.year, dt.mon, dt.day));

   if(today != g_currentDay)
   {
      g_currentDay       = today;
      g_signalFiredToday = false;
      g_tradesToday      = 0;
      g_partialDone      = false;
   }
}

//+------------------------------------------------------------------+
bool IsTradingDay()
{
   MqlDateTime dt;
   TimeCurrent(dt);

   switch(dt.day_of_week)
   {
      case 0: return TradeSunday;
      case 1: return TradeMonday;
      case 2: return TradeTuesday;
      case 3: return TradeWednesday;
      case 4: return TradeThursday;
      case 5: return TradeFriday;
      case 6: return TradeSaturday;
      default: return false;
   }
}

//+------------------------------------------------------------------+
bool IsInSessionWindow()
{
   MqlDateTime dt;
   TimeCurrent(dt);

   int nowMins   = dt.hour * 60 + dt.min;
   int startMins = StartHour * 60 + StartMin;
   int endMins   = EndHour * 60 + EndMin;

   // Handle same start/end (single bar window)
   // Allow the bar that starts at this time
   if(startMins == endMins)
   {
      // For M10: allow the current bar if it opened within this 10-min slot
      int barPeriodMins = PeriodSeconds(_Period) / 60;
      return (nowMins >= startMins && nowMins < startMins + barPeriodMins);
   }

   // Normal range
   if(endMins > startMins)
      return (nowMins >= startMins && nowMins <= endMins);
   else
      // Wraps midnight (unlikely but safe)
      return (nowMins >= startMins || nowMins <= endMins);
}

//+------------------------------------------------------------------+
//| POSITION HELPERS                                                  |
//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         return true;
   }
   return false;
}

//+------------------------------------------------------------------+
int CountTradesToday()
{
   int count = 0;
   datetime sod = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));

   // Open positions opened today
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         if(m_pos.Time() >= sod) count++;
   }

   // Closed deals today
   HistorySelect(sod, sod + 86400);
   for(int i = HistoryDealsTotal() - 1; i >= 0; i--)
   {
      ulong tk = HistoryDealGetTicket(i);
      if(tk == 0) continue;
      if(HistoryDealGetInteger(tk, DEAL_MAGIC) == MagicNumber &&
         HistoryDealGetString(tk, DEAL_SYMBOL) == _Symbol &&
         HistoryDealGetInteger(tk, DEAL_ENTRY) == DEAL_ENTRY_IN)
         count++;
   }
   return count;
}

//+------------------------------------------------------------------+
double GetDailyPnL()
{
   double pnl = 0;
   datetime sod = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));

   // Closed deals P/L
   HistorySelect(sod, sod + 86400);
   for(int i = HistoryDealsTotal() - 1; i >= 0; i--)
   {
      ulong tk = HistoryDealGetTicket(i);
      if(tk == 0) continue;
      if(HistoryDealGetInteger(tk, DEAL_MAGIC) == MagicNumber &&
         HistoryDealGetString(tk, DEAL_SYMBOL) == _Symbol &&
         HistoryDealGetInteger(tk, DEAL_ENTRY) == DEAL_ENTRY_OUT)
      {
         pnl += HistoryDealGetDouble(tk, DEAL_PROFIT)
              + HistoryDealGetDouble(tk, DEAL_SWAP)
              + HistoryDealGetDouble(tk, DEAL_COMMISSION);
      }
   }

   // Floating P/L
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         pnl += m_pos.Profit() + m_pos.Swap() + m_pos.Commission();
   }
   return pnl;
}

//+------------------------------------------------------------------+
//| CLOSE HELPERS                                                     |
//+------------------------------------------------------------------+
void CloseAllPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         m_trade.PositionClose(m_pos.Ticket());
   }
   Print("CTR: All positions closed.");
}

//+------------------------------------------------------------------+
void CloseWinningPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         if(m_pos.Profit() > 0)
            m_trade.PositionClose(m_pos.Ticket());
   }
   Print("CTR: Winners closed.");
}

