//+------------------------------------------------------------------+
void UpdateDashboard()
{
   if(!ShowChartComment) return;

   // Status
   string status = g_signalFiredToday ? "Signal Fired" : "Active";
   color  clrSt  = g_signalFiredToday ? clrOrange : clrLime;
   if(!IsTradingDay()) { status = "Day Off"; clrSt = clrDarkGray; }
   else if(!IsInSessionWindow()) { status = "Waiting"; clrSt = clrYellow; }
   SetLbl(DP+"V1", status, clrSt);

   // Spread
   long sp = SymbolInfoInteger(_Symbol, SYMBOL_SPREAD);
   color clrSp = (sp > MaxSpreadPoints) ? clrRed : clrWhite;
   SetLbl(DP+"V2", IntegerToString(sp) + " pts", clrSp);

   // Daily P/L
   double pnl = GetDailyPnL();
   string sign = pnl >= 0 ? "+$" : "-$";
   color clrPnl = pnl >= 0 ? clrLime : clrRed;
   SetLbl(DP+"V3", sign + DoubleToString(MathAbs(pnl), 2), clrPnl);

   // Trade count
   SetLbl(DP+"V4", IntegerToString(g_tradesToday) + "/" + IntegerToString(MaxTradesPerDay), clrWhite);

   // Swing levels
   double swH = 0, swL = 0;
   if(FindNearestSwingHigh(swH))
      SetLbl(DP+"V5", DoubleToString(swH, _Digits), clrCoral);
   else
      SetLbl(DP+"V5", "---", clrDarkGray);

   if(FindNearestSwingLow(swL))
      SetLbl(DP+"V6", DoubleToString(swL, _Digits), clrMediumSpringGreen);
   else
      SetLbl(DP+"V6", "---", clrDarkGray);

   // Signal status
   if(g_signalFiredToday)
      SetLbl(DP+"V8", "Done for today", clrOrange);
   else if(IsInSessionWindow())
      SetLbl(DP+"V8", "Scanning...", clrYellow);
   else
      SetLbl(DP+"V8", "Outside window", clrDarkGray);

   // Pause button text
   ObjectSetString(0, DP+"BtnPause", OBJPROP_TEXT,
                   g_signalFiredToday ? "Reset" : "Pause");
}

