   TimeCurrent(dt);
   datetime today = StringToTime(StringFormat("%d.%02d.%02d", dt.year, dt.mon, dt.day));

   if(today != g_currentDay)
   {
      g_currentDay       = today;
      g_signalFiredToday = false;
      g_tradesToday      = 0;
      g_partialDone      = false;
   }
}

//+------------------------------------------------------------------+
bool IsTradingDay()
{
   MqlDateTime dt;
   TimeCurrent(dt);

   switch(dt.day_of_week)
   {
      case 0: return TradeSunday;
      case 1: return TradeMonday;
      case 2: return TradeTuesday;
      case 3: return TradeWednesday;
      case 4: return TradeThursday;
      case 5: return TradeFriday;
      case 6: return TradeSaturday;
      default: return false;
   }
}

//+------------------------------------------------------------------+
bool IsInSessionWindow()
{
   MqlDateTime dt;
   TimeCurrent(dt);

   int nowMins   = dt.hour * 60 + dt.min;
   int startMins = StartHour * 60 + StartMin;
   int endMins   = EndHour * 60 + EndMin;

   // Handle same start/end (single bar window)
   // Allow the bar that starts at this time
   if(startMins == endMins)
   {
      // For M10: allow the current bar if it opened within this 10-min slot
      int barPeriodMins = PeriodSeconds(_Period) / 60;
      return (nowMins >= startMins && nowMins < startMins + barPeriodMins);
   }

   // Normal range
   if(endMins > startMins)
      return (nowMins >= startMins && nowMins <= endMins);
   else
      // Wraps midnight (unlikely but safe)
      return (nowMins >= startMins || nowMins <= endMins);
}

