   ObjectSetInteger(0,n,OBJPROP_BGCOLOR,bg);
   ObjectSetInteger(0,n,OBJPROP_BORDER_COLOR,C'50,50,70');
   ObjectSetInteger(0,n,OBJPROP_FONTSIZE,8);
