{"language": "plaintext", "code": "//+------------------------------------------------------------------+
//|                                            CTR_Reclaim_v2.mq5    |
//|        Counter Trend Reclaim — Liquidity Sweep Reversal EA       |
//|        Definitive version from video transcript + .set files     |
//+------------------------------------------------------------------+
#property copyright   "CTR Reclaim v2.0"
#property version     "2.00"
#property description "Marks HIGH/LOW of a specific candle at a key time."
#property description "Waits for price to sweep one level and close back inside."
#property description "Entry on next bar open after confirmed reclaim."
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>
#include <Trade\AccountInfo.mqh>

//+------------------------------------------------------------------+
//| ENUMS                                                             |
//+------------------------------------------------------------------+
enum ENUM_TRADE_DIR
{
   DIR_Both  = 0,  // Both (Buy & Sell)
   DIR_Buy   = 1,  // Buy only
   DIR_Sell  = 2   // Sell only
};

//+------------------------------------------------------------------+
//| INPUT PARAMETERS                                                  |
//+------------------------------------------------------------------+
input group "══════ GENERAL ══════"
input int              MagicNumber       = 1010;        // Magic Number
input double           RiskPercent       = 1.0;         // Risk per trade (% of balance)
input double           FixedLots         = 0.0;         // Fixed lots (0 = use Risk%)
input int              SL_ticks          = 110;         // Stop Loss (ticks/points)
input int              TP_ticks          = 290;         // Take Profit (ticks/points)
input int              MaxTradesPerDay   = 1;           // Max trades per day
input int              MaxSpreadPoints   = 30;          // Max spread (points)
input int              SlippagePoints    = 10;          // Max slippage (points)
input ENUM_TRADE_DIR   TradeType         = DIR_Both;    // Trade direction filter

input group "══════ KEY CANDLE TIME (broker server time) ══════"
input int              CandleHour        = 15;          // Key candle hour (server time)
input int              CandleMinute      = 45;          // Key candle minute (server time)

input group "══════ SIGNAL WINDOW ══════"
input int              WindowBars        = 12;          // Max bars to wait for sweep after key candle
input int              StartHour         = 15;          // Window start hour (for .set compat)
input int              StartMin          = 45;          // Window start minute
input int              EndHour           = 16;          // Window end hour
input int              EndMin            = 50;          // Window end minute

input group "══════ DAY FILTER ══════"
input bool             TradeSunday       = false;       // Trade Sunday
input bool             TradeMonday       = true;        // Trade Monday
input bool             TradeTuesday      = true;        // Trade Tuesday
input bool             TradeWednesday    = false;       // Trade Wednesday
input bool             TradeThursday     = false;       // Trade Thursday
input bool             TradeFriday       = true;        // Trade Friday
input bool             TradeSaturday     = false;       // Trade Saturday

input group "══════ BREAK EVEN (optional) ══════"
input bool             EnableBreakeven   = false;       // Enable Break Even
input int              BE_TriggerTicks   = 150;         // BE activation (ticks in profit)
input int              BE_OffsetTicks    = 10;          // Lock-in above entry (ticks)

input group "══════ PARTIAL CLOSE (optional) ══════"
input bool             EnablePartials    = false;       // Enable partial close
input double           PartialPercent    = 50.0;        // % of position to close
input int              PartialTrigTicks  = 200;         // Partial trigger (ticks in profit)

input group "══════ DISPLAY ══════"
input bool             ShowChartComment  = true;        // Show dashboard on chart
input bool             DrawLevels        = true;        // Draw key candle H/L on chart
input color            ColorHigh         = clrCoral;    // High level color
input color            ColorLow          = clrMediumSpringGreen; // Low level color

//+------------------------------------------------------------------+
//| GLOBAL STATE                                                      |
//+------------------------------------------------------------------+
CTrade         m_trade;
CPositionInfo  m_pos;
CAccountInfo   m_account;

datetime       g_lastBarTime;
datetime       g_currentDay;

// ── Key candle state (resets daily) ──
bool           g_candleMarked;       // did we find and mark today's key candle?
double         g_keyHigh;            // high of the key candle
double         g_keyLow;             // low of the key candle
datetime       g_keyCandleTime;      // time of the key candle
int            g_barsSinceKey;       // bars elapsed since key candle

// ── Signal state ──
bool           g_signalFiredToday;
int            g_tradesToday;
bool           g_partialDone;

// Dashboard
string         DP = "CTR_";
int            g_dashX = 20, g_dashY = 30;

//+------------------------------------------------------------------+
//| INITIALIZATION                                                    |
//+------------------------------------------------------------------+
int OnInit()
{
   m_trade.SetExpertMagicNumber(MagicNumber);
   m_trade.SetDeviationInPoints(SlippagePoints);
   m_trade.SetTypeFilling(ORDER_FILLING_IOC);

   // Reset state
   g_lastBarTime      = 0;
   g_currentDay       = 0;
   g_candleMarked     = false;
   g_keyHigh          = 0;
   g_keyLow           = 0;
   g_keyCandleTime    = 0;
   g_barsSinceKey     = 0;
   g_signalFiredToday = false;
   g_tradesToday      = 0;
   g_partialDone      = false;

   if(ShowChartComment)
      CreateDashboard();

   Print("═══════════════════════════════════════════════════════");
   Print("  CTR Reclaim v2.0 — Key Candle Logic");
   Print("  Symbol: ", _Symbol, " | TF: ", EnumToString(_Period));
   Print("  Key candle: ", StringFormat("%02d:%02d", CandleHour, CandleMinute), " server time");
   Print("  SL: ", SL_ticks, " ticks | TP: ", TP_ticks, " ticks (R:R 1:",
         DoubleToString((double)TP_ticks / SL_ticks, 2), ")");
   Print("═══════════════════════════════════════════════════════");

   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
//| DEINITIALIZATION                                                  |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   ObjectsDeleteAll(0, DP);
   Comment("");
}

//+------------------------------------------------------------------+
//| TICK FUNCTION                                                     |
//+------------------------------------------------------------------+
void OnTick()
{
   if(ShowChartComment) UpdateDashboard();
   ManageOpenPositions();

   if(!IsNewBar()) return;

   // ── Daily reset ──
   CheckDayReset();
   g_tradesToday = CountTradesToday();

   // ── Day filter ──
   if(!IsTradingDay()) return;

   // ── Step 1: Try to mark today's key candle ──
   if(!g_candleMarked)
   {
      TryMarkKeyCandle();
      return;  // if just marked, wait for next bar to check sweep
   }

   // ── Step 2: Count bars since key candle ──
   g_barsSinceKey++;

   // ── Expire if too many bars passed ──
   if(g_barsSinceKey > WindowBars)
   {
      // Also check time-based window
      if(!IsInTimeWindow())
         return;
   }

   // ── Guards ──
   if(g_signalFiredToday)              return;
   if(g_tradesToday >= MaxTradesPerDay) return;
   if(HasOpenPosition())               return;

   // Spread filter
   long spread = SymbolInfoInteger(_Symbol, SYMBOL_SPREAD);
   if(spread > MaxSpreadPoints)
   {
      Print("CTR: Spread ", spread, " > max ", MaxSpreadPoints, ". Skip.");
      return;
   }

   // ── Step 3: Check for sweep + reclaim on last closed bar ──
   CheckForSweepReclaim();
}

//+------------------------------------------------------------------+
//| MARK THE KEY CANDLE                                               |
//| Scans bar[1] to see if it IS the key candle (opened at key time) |
//+------------------------------------------------------------------+
void TryMarkKeyCandle()
{
   // Check bar[1] (last closed bar) — was it the key candle?
   datetime barTime = iTime(_Symbol, _Period, 1);
   MqlDateTime dt;
   TimeToStruct(barTime, dt);

   if(dt.hour == CandleHour && dt.min == CandleMinute)
   {
      g_keyHigh      = iHigh(_Symbol, _Period, 1);
      g_keyLow       = iLow(_Symbol, _Period, 1);
      g_keyCandleTime = barTime;
      g_candleMarked = true;
      g_barsSinceKey = 0;

      // Draw levels on chart
      if(DrawLevels)
      {
         DrawKeyLevel(DP + "KeyH_" + TimeToString(barTime), g_keyHigh, ColorHigh, "CTR High");
         DrawKeyLevel(DP + "KeyL_" + TimeToString(barTime), g_keyLow, ColorLow, "CTR Low");
      }

      Print("✦ CTR Key candle marked at ", TimeToString(barTime),
            " | H=", DoubleToString(g_keyHigh, _Digits),
            " | L=", DoubleToString(g_keyLow, _Digits),
            " | Range=", DoubleToString((g_keyHigh - g_keyLow) / _Point, 0), " ticks");
   }
}

//+------------------------------------------------------------------+
//| CHECK FOR SWEEP + RECLAIM                                         |
//| Core logic: did bar[1] sweep a level and close back inside?      |
//+------------------------------------------------------------------+
void CheckForSweepReclaim()
{
   double bHigh  = iHigh(_Symbol, _Period, 1);
   double bLow   = iLow(_Symbol, _Period, 1);
   double bClose = iClose(_Symbol, _Period, 1);
   double bOpen  = iOpen(_Symbol, _Period, 1);

   // ════════════════════════════════════════════
   // BULLISH SWEEP: wick below key low, close inside range
   // "Manipulación por debajo" — sweeps stops below, closes back above low
   // ════════════════════════════════════════════
   if(TradeType != DIR_Sell)
   {
      if(bLow < g_keyLow && bClose > g_keyLow)
      {
         // Confirmed bullish reclaim — enter BUY on next bar open
         ExecuteBuy(bLow, bClose);
         return;
      }
   }

   // ════════════════════════════════════════════
   // BEARISH SWEEP: wick above key high, close inside range
   // "Manipulación por arriba" — sweeps stops above, closes back below high
   // ════════════════════════════════════════════
   if(TradeType != DIR_Buy)
   {
      if(bHigh > g_keyHigh && bClose < g_keyHigh)
      {
         // Confirmed bearish reclaim — enter SELL on next bar open
         ExecuteSell(bHigh, bClose);
         return;
      }
   }
}

//+------------------------------------------------------------------+
//| EXECUTE BUY                                                       |
//+------------------------------------------------------------------+
void ExecuteBuy(double sweepLow, double reclaimClose)
{
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double sl  = NormalizeDouble(ask - SL_ticks * _Point, _Digits);
   double tp  = NormalizeDouble(ask + TP_ticks * _Point, _Digits);
   double lots = CalculateLotSize();
   if(lots <= 0) return;

   if(m_trade.Buy(lots, _Symbol, ask, sl, tp, "CTR BUY"))
   {
      g_signalFiredToday = true;
      g_partialDone      = false;
      Print("✓ CTR BUY | Key H=", DoubleToString(g_keyHigh, _Digits),
            " L=", DoubleToString(g_keyLow, _Digits),
            " | Sweep low=", DoubleToString(sweepLow, _Digits),
            " | Reclaim close=", DoubleToString(reclaimClose, _Digits),
            " | Entry=", DoubleToString(ask, _Digits),
            " | Lots=", DoubleToString(lots, 2));
   }
   else
      Print("✗ CTR BUY FAILED: ", m_trade.ResultRetcodeDescription());
}

//+------------------------------------------------------------------+
//| EXECUTE SELL                                                      |
//+------------------------------------------------------------------+
void ExecuteSell(double sweepHigh, double reclaimClose)
{
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double sl  = NormalizeDouble(bid + SL_ticks * _Point, _Digits);
   double tp  = NormalizeDouble(bid - TP_ticks * _Point, _Digits);
   double lots = CalculateLotSize();
   if(lots <= 0) return;

   if(m_trade.Sell(lots, _Symbol, bid, sl, tp, "CTR SELL"))
   {
      g_signalFiredToday = true;
      g_partialDone      = false;
      Print("✓ CTR SELL | Key H=", DoubleToString(g_keyHigh, _Digits),
            " L=", DoubleToString(g_keyLow, _Digits),
            " | Sweep high=", DoubleToString(sweepHigh, _Digits),
            " | Reclaim close=", DoubleToString(reclaimClose, _Digits),
            " | Entry=", DoubleToString(bid, _Digits),
            " | Lots=", DoubleToString(lots, 2));
   }
   else
      Print("✗ CTR SELL FAILED: ", m_trade.ResultRetcodeDescription());
}

//+------------------------------------------------------------------+
//| LOT SIZE CALCULATION                                              |
//+------------------------------------------------------------------+
double CalculateLotSize()
{
   if(FixedLots > 0)
      return NormalizeLots(FixedLots);

   double balance    = m_account.Balance();
   double riskAmount = balance * RiskPercent / 100.0;
   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickValue <= 0 || tickSize <= 0)
   {
      Print("CTR: Invalid tick value/size. Using min lot.");
      return SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   }

   double slPrice    = SL_ticks * _Point;
   double lossPerLot = (slPrice / tickSize) * tickValue;

   if(lossPerLot <= 0) return SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);

   return NormalizeLots(riskAmount / lossPerLot);
}

//+------------------------------------------------------------------+
double NormalizeLots(double lots)
{
   double minL = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxL = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double step = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   if(step <= 0) step = 0.01;

   lots = MathFloor(lots / step) * step;
   lots = MathMax(lots, minL);
   lots = MathMin(lots, maxL);
   return NormalizeDouble(lots, 2);
}

//+------------------------------------------------------------------+
//| POSITION MANAGEMENT — BE & Partials                               |
//+------------------------------------------------------------------+
void ManageOpenPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i))           continue;
      if(m_pos.Magic() != MagicNumber)       continue;
      if(m_pos.Symbol() != _Symbol)          continue;

      double entry = m_pos.PriceOpen();
      double curSL = m_pos.StopLoss();
      double curTP = m_pos.TakeProfit();
      ulong  tkt   = m_pos.Ticket();

      if(m_pos.PositionType() == POSITION_TYPE_BUY)
      {
         double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
         double profTicks = (bid - entry) / _Point;

         // Break even
         if(EnableBreakeven && profTicks >= BE_TriggerTicks)
         {
            double newSL = NormalizeDouble(entry + BE_OffsetTicks * _Point, _Digits);
            if(curSL < newSL)
               m_trade.PositionModify(tkt, newSL, curTP);
         }

         // Partial close
         if(EnablePartials && !g_partialDone && profTicks >= PartialTrigTicks)
         {
            double closeLots = NormalizeLots(m_pos.Volume() * PartialPercent / 100.0);
            if(closeLots > 0 && closeLots < m_pos.Volume())
            {
               m_trade.PositionClosePartial(tkt, closeLots);
               g_partialDone = true;
            }
         }
      }
      else if(m_pos.PositionType() == POSITION_TYPE_SELL)
      {
         double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
         double profTicks = (entry - ask) / _Point;

         if(EnableBreakeven && profTicks >= BE_TriggerTicks)
         {
            double newSL = NormalizeDouble(entry - BE_OffsetTicks * _Point, _Digits);
            if(curSL > newSL || curSL == 0)
               m_trade.PositionModify(tkt, newSL, curTP);
         }

         if(EnablePartials && !g_partialDone && profTicks >= PartialTrigTicks)
         {
            double closeLots = NormalizeLots(m_pos.Volume() * PartialPercent / 100.0);
            if(closeLots > 0 && closeLots < m_pos.Volume())
            {
               m_trade.PositionClosePartial(tkt, closeLots);
               g_partialDone = true;
            }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| TIME & DAY HELPERS                                                |
//+------------------------------------------------------------------+
bool IsNewBar()
{
   datetime t = iTime(_Symbol, _Period, 0);
   if(t == g_lastBarTime) return false;
   g_lastBarTime = t;
   return true;
}

//+------------------------------------------------------------------+
void CheckDayReset()
{
   MqlDateTime dt;
   TimeCurrent(dt);
   datetime today = StringToTime(StringFormat("%d.%02d.%02d", dt.year, dt.mon, dt.day));

   if(today != g_currentDay)
   {
      g_currentDay       = today;
      g_candleMarked     = false;
      g_keyHigh          = 0;
      g_keyLow           = 0;
      g_keyCandleTime    = 0;
      g_barsSinceKey     = 0;
      g_signalFiredToday = false;
      g_tradesToday      = 0;
      g_partialDone      = false;
   }
}

//+------------------------------------------------------------------+
bool IsTradingDay()
{
   MqlDateTime dt;
   TimeCurrent(dt);
   switch(dt.day_of_week)
   {
      case 0: return TradeSunday;
      case 1: return TradeMonday;
      case 2: return TradeTuesday;
      case 3: return TradeWednesday;
      case 4: return TradeThursday;
      case 5: return TradeFriday;
      case 6: return TradeSaturday;
   }
   return false;
}

//+------------------------------------------------------------------+
bool IsInTimeWindow()
{
   MqlDateTime dt;
   TimeCurrent(dt);
   int now   = dt.hour * 60 + dt.min;
   int start = StartHour * 60 + StartMin;
   int end   = EndHour * 60 + EndMin;

   if(start == end)
   {
      int barMins = PeriodSeconds(_Period) / 60;
      return (now >= start && now < start + barMins);
   }
   if(end > start)
      return (now >= start && now <= end);
   return (now >= start || now <= end);
}

//+------------------------------------------------------------------+
//| POSITION HELPERS                                                  |
//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         return true;
   }
   return false;
}

//+------------------------------------------------------------------+
int CountTradesToday()
{
   int count = 0;
   datetime sod = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));

   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         if(m_pos.Time() >= sod) count++;
   }

   HistorySelect(sod, sod + 86400);
   for(int i = HistoryDealsTotal() - 1; i >= 0; i--)
   {
      ulong tk = HistoryDealGetTicket(i);
      if(tk == 0) continue;
      if(HistoryDealGetInteger(tk, DEAL_MAGIC) == MagicNumber &&
         HistoryDealGetString(tk, DEAL_SYMBOL) == _Symbol &&
         HistoryDealGetInteger(tk, DEAL_ENTRY) == DEAL_ENTRY_IN)
         count++;
   }
   return count;
}

//+------------------------------------------------------------------+
double GetDailyPnL()
{
   double pnl = 0;
   datetime sod = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));

   HistorySelect(sod, sod + 86400);
   for(int i = HistoryDealsTotal() - 1; i >= 0; i--)
   {
      ulong tk = HistoryDealGetTicket(i);
      if(tk == 0) continue;
      if(HistoryDealGetInteger(tk, DEAL_MAGIC) == MagicNumber &&
         HistoryDealGetString(tk, DEAL_SYMBOL) == _Symbol &&
         HistoryDealGetInteger(tk, DEAL_ENTRY) == DEAL_ENTRY_OUT)
         pnl += HistoryDealGetDouble(tk, DEAL_PROFIT)
              + HistoryDealGetDouble(tk, DEAL_SWAP)
              + HistoryDealGetDouble(tk, DEAL_COMMISSION);
   }

   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         pnl += m_pos.Profit() + m_pos.Swap() + m_pos.Commission();
   }
   return pnl;
}

//+------------------------------------------------------------------+
//| CLOSE HELPERS                                                     |
//+------------------------------------------------------------------+
void CloseAllPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         m_trade.PositionClose(m_pos.Ticket());
   }
}

void CloseWinningPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         if(m_pos.Profit() > 0)
            m_trade.PositionClose(m_pos.Ticket());
   }
}

//+------------------------------------------------------------------+
//| CHART DRAWING                                                     |
//+------------------------------------------------------------------+
void DrawKeyLevel(string name, double price, color clr, string label)
{
   if(ObjectFind(0, name) >= 0)
      ObjectDelete(0, name);

   ObjectCreate(0, name, OBJ_HLINE, 0, 0, price);
   ObjectSetInteger(0, name, OBJPROP_COLOR, clr);
   ObjectSetInteger(0, name, OBJPROP_STYLE, STYLE_DASHDOTDOT);
   ObjectSetInteger(0, name, OBJPROP_WIDTH, 1);
   ObjectSetString(0, name, OBJPROP_TEXT, label + " " + DoubleToString(price, _Digits));
   ObjectSetInteger(0, name, OBJPROP_SELECTABLE, false);
   ObjectSetInteger(0, name, OBJPROP_BACK, true);
}

//+------------------------------------------------------------------+
//| CHART EVENTS — Button clicks                                      |
//+------------------------------------------------------------------+
void OnChartEvent(const int id, const long &lparam,
                  const double &dparam, const string &sparam)
{
   if(id != CHARTEVENT_OBJECT_CLICK) return;

   if(sparam == DP + "BtnCloseAll")
   {
      CloseAllPositions();
      ObjectSetInteger(0, sparam, OBJPROP_STATE, false);
   }
   else if(sparam == DP + "BtnCloseWin")
   {
      CloseWinningPositions();
      ObjectSetInteger(0, sparam, OBJPROP_STATE, false);
   }
   else if(sparam == DP + "BtnPause")
   {
      g_signalFiredToday = !g_signalFiredToday;
      ObjectSetInteger(0, sparam, OBJPROP_STATE, false);
   }
}

//+------------------------------------------------------------------+
//| DASHBOARD                                                         |
//+------------------------------------------------------------------+
void CreateDashboard()
{
   int w = 260, h = 290;
   CreateRect(DP+"BG", g_dashX, g_dashY, w, h, C'18,18,28', C'45,45,65');
   CreateRect(DP+"TBar", g_dashX, g_dashY, w, 28, C'35,35,55', C'45,45,65');
   CreateLbl(DP+"Title", g_dashX+10, g_dashY+6, "CTR Reclaim v2.0", clrWhite, 10, "Arial Bold");

   int y0 = g_dashY + 36, rh = 18;
   CreateLbl(DP+"L1", g_dashX+10, y0,       "Status:",     clrGray, 9, "Arial");
   CreateLbl(DP+"V1", g_dashX+105, y0,      "Init",        clrYellow, 9, "Arial Bold");
   CreateLbl(DP+"L2", g_dashX+10, y0+rh,    "Spread:",     clrGray, 9, "Arial");
   CreateLbl(DP+"V2", g_dashX+105, y0+rh,   "0",           clrWhite, 9, "Arial");
   CreateLbl(DP+"L3", g_dashX+10, y0+rh*2,  "Daily P/L:",  clrGray, 9, "Arial");
   CreateLbl(DP+"V3", g_dashX+105, y0+rh*2, "$0.00",       clrWhite, 9, "Arial");
   CreateLbl(DP+"L4", g_dashX+10, y0+rh*3,  "Trades:",     clrGray, 9, "Arial");
   CreateLbl(DP+"V4", g_dashX+105, y0+rh*3, "0/"+IntegerToString(MaxTradesPerDay), clrWhite, 9, "Arial");

   CreateLbl(DP+"Sep", g_dashX+10, y0+rh*4, "─────────────────────────", C'45,45,65', 8, "Arial");

   CreateLbl(DP+"L5", g_dashX+10, y0+rh*5,  "Key candle:", clrGray, 9, "Arial");
   CreateLbl(DP+"V5", g_dashX+105, y0+rh*5, "Not marked",  clrDarkGray, 9, "Arial");
   CreateLbl(DP+"L6", g_dashX+10, y0+rh*6,  "Key High:",   clrGray, 9, "Arial");
   CreateLbl(DP+"V6", g_dashX+105, y0+rh*6, "---",         ColorHigh, 9, "Arial");
