//+------------------------------------------------------------------+
void UpdateDashboard()
{
   if(!ShowChartComment) return;

   // Status
   string status; color clrSt;
   if(!IsTradingDay())              { status = "Day Off";       clrSt = clrDarkGray; }
   else if(g_signalFiredToday)      { status = "Done";          clrSt = clrOrange; }
   else if(!g_candleMarked)         { status = "Waiting candle"; clrSt = clrYellow; }
   else if(HasOpenPosition())       { status = "In Trade";      clrSt = clrDodgerBlue; }
   else                             { status = "Scanning";      clrSt = clrLime; }
   SetLbl(DP+"V1", status, clrSt);

   // Spread
   long sp = SymbolInfoInteger(_Symbol, SYMBOL_SPREAD);
   SetLbl(DP+"V2", IntegerToString(sp) + " pts", sp > MaxSpreadPoints ? clrRed : clrWhite);

   // P/L
   double pnl = GetDailyPnL();
   SetLbl(DP+"V3", (pnl>=0?"+$":"-$") + DoubleToString(MathAbs(pnl),2), pnl>=0?clrLime:clrRed);

   // Trades
   SetLbl(DP+"V4", IntegerToString(g_tradesToday)+"/"+IntegerToString(MaxTradesPerDay), clrWhite);

   // Key candle info
   if(g_candleMarked)
   {
      SetLbl(DP+"V5", TimeToString(g_keyCandleTime, TIME_MINUTES), clrWhite);
      SetLbl(DP+"V6", DoubleToString(g_keyHigh, _Digits), ColorHigh);
      SetLbl(DP+"V7", DoubleToString(g_keyLow, _Digits), ColorLow);
      SetLbl(DP+"V8", IntegerToString(g_barsSinceKey)+"/"+IntegerToString(WindowBars), clrWhite);
   }
   else
   {
      SetLbl(DP+"V5", "Not yet", clrDarkGray);
      SetLbl(DP+"V6", "---", clrDarkGray);
      SetLbl(DP+"V7", "---", clrDarkGray);
      SetLbl(DP+"V8", "-", clrDarkGray);
   }

   // Signal
   if(g_signalFiredToday)
      SetLbl(DP+"V9", "Fired today", clrOrange);
   else if(g_candleMarked)
      SetLbl(DP+"V9", "Watching sweep...", clrYellow);
   else
      SetLbl(DP+"V9", "Waiting candle", clrDarkGray);
}

