   199	//+------------------------------------------------------------------+
   200	//| MARK THE KEY CANDLE                                               |
   201	//| Scans bar[1] to see if it IS the key candle (opened at key time) |
   202	//+------------------------------------------------------------------+
   203	void TryMarkKeyCandle()
   204	{
   205	   // Check bar[1] (last closed bar) — was it the key candle?
   206	   datetime barTime = iTime(_Symbol, _Period, 1);
   207	   MqlDateTime dt;
   208	   TimeToStruct(barTime, dt);
   209	
   210	   if(dt.hour == CandleHour && dt.min == CandleMinute)
   211	   {
   212	      g_keyHigh      = iHigh(_Symbol, _Period, 1);
   213	      g_keyLow       = iLow(_Symbol, _Period, 1);
   214	      g_keyCandleTime = barTime;
   215	      g_candleMarked = true;
   216	      g_barsSinceKey = 0;
   217	
   218	      // Draw levels on chart
   219	      if(DrawLevels)
   220	      {
   221	         DrawKeyLevel(DP + "KeyH_" + TimeToString(barTime), g_keyHigh, ColorHigh, "CTR High");
   222	         DrawKeyLevel(DP + "KeyL_" + TimeToString(barTime), g_keyLow, ColorLow, "CTR Low");
   223	      }
   224	
   225	      Print("✦ CTR Key candle marked at ", TimeToString(barTime),
   226	            " | H=", DoubleToString(g_keyHigh, _Digits),
   227	            " | L=", DoubleToString(g_keyLow, _Digits),
   228	            " | Range=", DoubleToString((g_keyHigh - g_keyLow) / _Point, 0), " ticks");
   229	   }
   230	}
   231	
   232	//+------------------------------------------------------------------+
   233	//| CHECK FOR SWEEP + RECLAIM                                         |
   234	//| Core logic: did bar[1] sweep a level and close back inside?      |
   235	//+------------------------------------------------------------------+
   236	void CheckForSweepReclaim()
   237	{
   238	   double bHigh  = iHigh(_Symbol, _Period, 1);
   239	   double bLow   = iLow(_Symbol, _Period, 1);
   240	   double bClose = iClose(_Symbol, _Period, 1);
   241	   double bOpen  = iOpen(_Symbol, _Period, 1);
   242	
   243	   // ════════════════════════════════════════════
   244	   // BULLISH SWEEP: wick below key low, close inside range
   245	   // "Manipulación por debajo" — sweeps stops below, closes back above low
   246	   // ════════════════════════════════════════════
   247	   if(TradeType != DIR_Sell)
   248	   {
   249	      if(bLow < g_keyLow && bClose > g_keyLow)
   250	      {
   251	         // Confirmed bullish reclaim — enter BUY on next bar open
   252	         ExecuteBuy(bLow, bClose);
   253	         return;
   254	      }
   255	   }
   256	
   257	   // ════════════════════════════════════════════
   258	   // BEARISH SWEEP: wick above key high, close inside range
   259	   // "Manipulación por arriba" — sweeps stops above, closes back below high
   260	   // ════════════════════════════════════════════
   261	   if(TradeType != DIR_Buy)
   262	   {
   263	      if(bHigh > g_keyHigh && bClose < g_keyHigh)
   264	      {
   265	         // Confirmed bearish reclaim — enter SELL on next bar open
   266	         ExecuteSell(bHigh, bClose);
   267	         return;
   268	      }
   269	   }
   270	}
