//+------------------------------------------------------------------+
//|                                          CTR_Reclaim_v2_1.mq5    |
//|        Counter Trend Reclaim — Liquidity Sweep Reversal EA       |
//|        v2.1 — All bugs fixed, debug logging, GMT offset          |
//+------------------------------------------------------------------+
#property copyright   "CTR Reclaim v2.1"
#property version     "2.10"
#property description "Marks HIGH/LOW of a specific candle at a key time."
#property description "Waits for sweep + reclaim. Entry on next bar open."
#property description "v2.1: Fixed key candle detection, fill mode, debug logs."
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>
#include <Trade\AccountInfo.mqh>

//+------------------------------------------------------------------+
//| ENUMS                                                             |
//+------------------------------------------------------------------+
enum ENUM_TRADE_DIR
{
   DIR_Both = 0,   // Both
   DIR_Buy  = 1,   // Buy only
   DIR_Sell = 2    // Sell only
};

//+------------------------------------------------------------------+
//| INPUTS                                                            |
//+------------------------------------------------------------------+
input group "══════ GENERAL ══════"
input int              MagicNumber       = 1010;
input double           RiskPercent       = 1.0;         // Risk % of balance
input double           FixedLots         = 0.0;         // Fixed lots (0=use risk%)
input int              SL_ticks          = 110;         // Stop Loss in ticks (points)
input int              TP_ticks          = 290;         // Take Profit in ticks (points)
input int              MaxTradesPerDay   = 1;
input int              MaxSpreadPoints   = 30;
input int              SlippagePoints    = 10;
input ENUM_TRADE_DIR   TradeType         = DIR_Both;

input group "══════ KEY CANDLE — NY TIME ══════"
input int              NY_Hour           = 8;           // NY hour of key candle (UTC-5)
input int              NY_Minute         = 45;          // NY minute of key candle
input int              GMT_Offset        = 2;           // Broker server GMT offset (e.g. 2 for GMT+2)

input group "══════ SIGNAL WINDOW ══════"
input int              WindowBars        = 12;          // Max bars after key candle to wait for sweep

input group "══════ DAY FILTER ══════"
input bool             TradeSunday       = false;
input bool             TradeMonday       = true;
input bool             TradeTuesday      = true;
input bool             TradeWednesday    = false;
input bool             TradeThursday     = false;
input bool             TradeFriday       = true;
input bool             TradeSaturday     = false;

input group "══════ BREAK EVEN ══════"
input bool             EnableBreakeven   = false;
input int              BE_TriggerTicks   = 150;
input int              BE_OffsetTicks    = 10;

input group "══════ PARTIAL CLOSE ══════"
input bool             EnablePartials    = false;
input double           PartialPercent    = 50.0;
input int              PartialTrigTicks  = 200;

input group "══════ DISPLAY ══════"
input bool             ShowDashboard     = true;
input bool             DrawLevels        = true;
input bool             DebugMode         = true;        // Print detailed logs
input color            ColorHigh         = clrCoral;
input color            ColorLow          = clrMediumSpringGreen;

//+------------------------------------------------------------------+
//| GLOBALS                                                           |
//+------------------------------------------------------------------+
CTrade         m_trade;
CPositionInfo  m_pos;
CAccountInfo   m_account;

datetime       g_lastBarTime;
datetime       g_currentDay;

// Key candle (computed from NY time + GMT offset)
int            g_serverHour;         // key candle hour in server time
int            g_serverMinute;       // key candle minute in server time

// Daily state
bool           g_candleMarked;
double         g_keyHigh;
double         g_keyLow;
datetime       g_keyCandleTime;
int            g_barsSinceKey;
bool           g_signalFiredToday;
int            g_tradesToday;
bool           g_partialDone;

// Dashboard
string         DP = "CTR_";

//+------------------------------------------------------------------+
//| INIT                                                              |
//+------------------------------------------------------------------+
int OnInit()
{
   // ── Calculate server time for key candle ──
   // NY is UTC-5, broker is UTC+GMT_Offset
   // Server hour = NY_Hour + 5 (to UTC) + GMT_Offset
   g_serverHour   = NY_Hour + 5 + GMT_Offset;
   g_serverMinute = NY_Minute;
   // Handle overflow
   if(g_serverHour >= 24) g_serverHour -= 24;
   if(g_serverHour < 0)   g_serverHour += 24;

   // ── Validate candle minute vs timeframe ──
   int tfMinutes = PeriodSeconds(_Period) / 60;
   if(tfMinutes > 0 && (g_serverMinute % tfMinutes) != 0)
   {
      // Snap down to nearest valid candle open time
      int snapped = (g_serverMinute / tfMinutes) * tfMinutes;
      Print("⚠ WARNING: Minute ", g_serverMinute, " is not a valid bar open on ",
            EnumToString(_Period), ". Snapping to :", snapped);
      g_serverMinute = snapped;
   }

   // ── Configure trade object ──
   m_trade.SetExpertMagicNumber(MagicNumber);
   m_trade.SetDeviationInPoints(SlippagePoints);

   // ── Auto-detect fill mode ──
   ENUM_SYMBOL_TRADE_EXECUTION execMode =
      (ENUM_SYMBOL_TRADE_EXECUTION)SymbolInfoInteger(_Symbol, SYMBOL_TRADE_EXEMODE);
   long fillFlags = SymbolInfoInteger(_Symbol, SYMBOL_FILLING_MODE);

   if((fillFlags & SYMBOL_FILLING_FOK) != 0)
      m_trade.SetTypeFilling(ORDER_FILLING_FOK);
   else if((fillFlags & SYMBOL_FILLING_IOC) != 0)
      m_trade.SetTypeFilling(ORDER_FILLING_IOC);
   else
      m_trade.SetTypeFilling(ORDER_FILLING_RETURN);

   // ── Reset state ──
   g_lastBarTime      = 0;
   g_currentDay       = 0;
   g_candleMarked     = false;
   g_keyHigh          = 0;
   g_keyLow           = 0;
   g_keyCandleTime    = 0;
   g_barsSinceKey     = 0;
   g_signalFiredToday = false;
   g_tradesToday      = 0;
   g_partialDone      = false;

   if(ShowDashboard) CreateDashboard();

   Print("═══════════════════════════════════════════════════════");
   Print("  CTR Reclaim v2.1");
   Print("  ", _Symbol, " | ", EnumToString(_Period));
   Print("  NY time: ", StringFormat("%02d:%02d", NY_Hour, NY_Minute),
         " → Server time: ", StringFormat("%02d:%02d", g_serverHour, g_serverMinute),
         " (GMT+", IntegerToString(GMT_Offset), ")");
   Print("  SL=", SL_ticks, " | TP=", TP_ticks,
         " | R:R 1:", DoubleToString((double)TP_ticks/SL_ticks, 2));
   Print("  Fill mode: ", EnumToString(m_trade.TypeFilling()));
   Print("═══════════════════════════════════════════════════════");

   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   ObjectsDeleteAll(0, DP);
   Comment("");
}

//+------------------------------------------------------------------+
//| TICK                                                              |
//+------------------------------------------------------------------+
void OnTick()
{
   if(ShowDashboard) UpdateDashboard();
   ManageOpenPositions();

   if(!IsNewBar()) return;

   // Daily reset
   CheckDayReset();
   g_tradesToday = CountTradesToday();

   // Day filter
   if(!IsTradingDay())
   {
      if(DebugMode && g_lastBarTime == iTime(_Symbol, _Period, 0))
      {} // suppress spam
      return;
   }

   // ── STEP 1: Find today's key candle if not yet found ──
   if(!g_candleMarked)
   {
      ScanForKeyCandle();
      // Don't return here — if we found it AND bars have passed,
      // we should immediately check for sweeps
   }

   // If still not marked, nothing to do
   if(!g_candleMarked) return;

   // ── STEP 2: Check if within window ──
   g_barsSinceKey = CountBarsSinceKeyCandle();

   if(g_barsSinceKey < 1)
      return;  // need at least 1 bar after key candle

   if(g_barsSinceKey > WindowBars)
   {
      if(DebugMode && g_barsSinceKey == WindowBars + 1)
         Print("CTR: Window expired. ", g_barsSinceKey, " bars since key candle.");
      return;
   }

   // ── Guards ──
   if(g_signalFiredToday)              return;
   if(g_tradesToday >= MaxTradesPerDay) return;
   if(HasOpenPosition())               return;

   // Spread
   long spread = SymbolInfoInteger(_Symbol, SYMBOL_SPREAD);
   if(spread > MaxSpreadPoints)
   {
      if(DebugMode)
         Print("CTR: Spread ", spread, " > max ", MaxSpreadPoints);
      return;
   }

   // ── STEP 3: Check sweep + reclaim on bar[1] ──
   CheckForSweepReclaim();
}

//+------------------------------------------------------------------+
//| SCAN FOR KEY CANDLE                                               |
//| Scans today's bars to find the key candle (might already have     |
//| passed if EA was loaded mid-session or in backtesting)            |
//+------------------------------------------------------------------+
void ScanForKeyCandle()
{
   datetime todayStart = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));
   int totalBars = Bars(_Symbol, _Period);

   // Scan from bar 1 backwards through today's bars
   for(int i = 1; i < MathMin(totalBars, 200); i++)
   {
      datetime barTime = iTime(_Symbol, _Period, i);

      // Stop if we've gone past today
      if(barTime < todayStart)
         break;

      MqlDateTime dt;
      TimeToStruct(barTime, dt);

      if(dt.hour == g_serverHour && dt.min == g_serverMinute)
      {
         g_keyHigh       = iHigh(_Symbol, _Period, i);
         g_keyLow        = iLow(_Symbol, _Period, i);
         g_keyCandleTime = barTime;
         g_candleMarked  = true;
         g_barsSinceKey  = 0; // will be recalculated

         if(DrawLevels)
         {
            string suffix = TimeToString(barTime, TIME_DATE);
            DrawKeyLevel(DP + "H_" + suffix, g_keyHigh, ColorHigh, "CTR High");
            DrawKeyLevel(DP + "L_" + suffix, g_keyLow, ColorLow, "CTR Low");
         }

         if(DebugMode)
            Print("✦ Key candle found at bar[", i, "] = ", TimeToString(barTime),
                  " | H=", DoubleToString(g_keyHigh, _Digits),
                  " | L=", DoubleToString(g_keyLow, _Digits),
                  " | Range=", DoubleToString((g_keyHigh - g_keyLow) / _Point, 0), " ticks");
         return;
      }
   }

   // Not found yet — log once per hour to avoid spam
   static int lastLogHour = -1;
   MqlDateTime nowDt;
   TimeCurrent(nowDt);
   if(DebugMode && nowDt.hour != lastLogHour)
   {
      lastLogHour = nowDt.hour;
      Print("CTR: Waiting for key candle at server ",
            StringFormat("%02d:%02d", g_serverHour, g_serverMinute),
            " | Current: ", StringFormat("%02d:%02d", nowDt.hour, nowDt.min));
   }
}

//+------------------------------------------------------------------+
//| COUNT BARS SINCE KEY CANDLE                                       |
//+------------------------------------------------------------------+
int CountBarsSinceKeyCandle()
{
   if(!g_candleMarked || g_keyCandleTime == 0) return 0;

   int shift = iBarShift(_Symbol, _Period, g_keyCandleTime);
   if(shift < 0) return 999; // key candle not found in history
   return shift; // bar[0] is current, so shift = number of bars since
}

//+------------------------------------------------------------------+
//| CHECK FOR SWEEP + RECLAIM                                         |
//+------------------------------------------------------------------+
void CheckForSweepReclaim()
{
   // Check ALL bars between key candle and now, not just bar[1]
   // This handles cases where the sweep might have happened several bars ago
   // but we need to check bar by bar from most recent backwards

   // Only check bar[1] (last completed bar) — the entry is on current bar open
   double bHigh  = iHigh(_Symbol, _Period, 1);
   double bLow   = iLow(_Symbol, _Period, 1);
   double bClose = iClose(_Symbol, _Period, 1);
   double bOpen  = iOpen(_Symbol, _Period, 1);

   if(DebugMode)
   {
      Print("CTR: Checking bar[1] | O=", DoubleToString(bOpen, _Digits),
            " H=", DoubleToString(bHigh, _Digits),
            " L=", DoubleToString(bLow, _Digits),
            " C=", DoubleToString(bClose, _Digits),
            " | Key H=", DoubleToString(g_keyHigh, _Digits),
            " L=", DoubleToString(g_keyLow, _Digits));
   }

   // ═══ BULLISH: swept low + closed back above ═══
   if(TradeType != DIR_Sell)
   {
      if(bLow < g_keyLow && bClose > g_keyLow)
      {
         if(DebugMode)
            Print("✓ BULLISH SWEEP DETECTED! Low ", DoubleToString(bLow, _Digits),
                  " < Key Low ", DoubleToString(g_keyLow, _Digits),
                  " & Close ", DoubleToString(bClose, _Digits), " > Key Low");
         ExecuteBuy(bLow, bClose);
         return;
      }
   }

   // ═══ BEARISH: swept high + closed back below ═══
   if(TradeType != DIR_Buy)
   {
      if(bHigh > g_keyHigh && bClose < g_keyHigh)
      {
         if(DebugMode)
            Print("✓ BEARISH SWEEP DETECTED! High ", DoubleToString(bHigh, _Digits),
                  " > Key High ", DoubleToString(g_keyHigh, _Digits),
                  " & Close ", DoubleToString(bClose, _Digits), " < Key High");
         ExecuteSell(bHigh, bClose);
         return;
      }
   }
}

//+------------------------------------------------------------------+
//| EXECUTE BUY                                                       |
//+------------------------------------------------------------------+
void ExecuteBuy(double sweepLow, double reclaimClose)
{
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double sl  = NormalizeDouble(ask - SL_ticks * _Point, _Digits);
   double tp  = NormalizeDouble(ask + TP_ticks * _Point, _Digits);
   double lots = CalculateLotSize();
   if(lots <= 0) { Print("CTR: Lot size = 0, cannot trade"); return; }

   Print("CTR: Sending BUY | Ask=", DoubleToString(ask, _Digits),
         " | SL=", DoubleToString(sl, _Digits),
         " | TP=", DoubleToString(tp, _Digits),
         " | Lots=", DoubleToString(lots, 2));

   if(m_trade.Buy(lots, _Symbol, ask, sl, tp, "CTR BUY"))
   {
      g_signalFiredToday = true;
      g_partialDone      = false;
      Print("✓ CTR BUY FILLED | Ticket=", m_trade.ResultOrder());
   }
   else
   {
      Print("✗ CTR BUY FAILED: code=", m_trade.ResultRetcode(),
            " | ", m_trade.ResultRetcodeDescription());
      // Retry without SL/TP (some brokers need modify after)
      if(m_trade.ResultRetcode() == TRADE_RETCODE_INVALID_STOPS)
      {
         Print("CTR: Retrying without SL/TP...");
         if(m_trade.Buy(lots, _Symbol, ask, 0, 0, "CTR BUY"))
         {
            g_signalFiredToday = true;
            g_partialDone      = false;
            // Modify to add SL/TP
            ulong ticket = m_trade.ResultOrder();
            if(ticket > 0)
               m_trade.PositionModify(ticket, sl, tp);
            Print("✓ CTR BUY FILLED (retry) | Ticket=", ticket);
         }
         else
            Print("✗ CTR BUY RETRY FAILED: ", m_trade.ResultRetcodeDescription());
      }
   }
}

//+------------------------------------------------------------------+
//| EXECUTE SELL                                                      |
//+------------------------------------------------------------------+
void ExecuteSell(double sweepHigh, double reclaimClose)
{
   double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double sl  = NormalizeDouble(bid + SL_ticks * _Point, _Digits);
   double tp  = NormalizeDouble(bid - TP_ticks * _Point, _Digits);
   double lots = CalculateLotSize();
   if(lots <= 0) { Print("CTR: Lot size = 0, cannot trade"); return; }

   Print("CTR: Sending SELL | Bid=", DoubleToString(bid, _Digits),
         " | SL=", DoubleToString(sl, _Digits),
         " | TP=", DoubleToString(tp, _Digits),
         " | Lots=", DoubleToString(lots, 2));

   if(m_trade.Sell(lots, _Symbol, bid, sl, tp, "CTR SELL"))
   {
      g_signalFiredToday = true;
      g_partialDone      = false;
      Print("✓ CTR SELL FILLED | Ticket=", m_trade.ResultOrder());
   }
   else
   {
      Print("✗ CTR SELL FAILED: code=", m_trade.ResultRetcode(),
            " | ", m_trade.ResultRetcodeDescription());
      if(m_trade.ResultRetcode() == TRADE_RETCODE_INVALID_STOPS)
      {
         Print("CTR: Retrying without SL/TP...");
         if(m_trade.Sell(lots, _Symbol, bid, 0, 0, "CTR SELL"))
         {
            g_signalFiredToday = true;
            g_partialDone      = false;
            ulong ticket = m_trade.ResultOrder();
            if(ticket > 0)
               m_trade.PositionModify(ticket, sl, tp);
            Print("✓ CTR SELL FILLED (retry) | Ticket=", ticket);
         }
         else
            Print("✗ CTR SELL RETRY FAILED: ", m_trade.ResultRetcodeDescription());
      }
   }
}

//+------------------------------------------------------------------+
//| LOT SIZE                                                          |
//+------------------------------------------------------------------+
double CalculateLotSize()
{
   if(FixedLots > 0)
      return NormalizeLots(FixedLots);

   double balance    = m_account.Balance();
   double riskAmount = balance * RiskPercent / 100.0;
   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

   if(tickValue <= 0 || tickSize <= 0)
   {
      Print("CTR: tickValue=", tickValue, " tickSize=", tickSize, " — using min lot");
      return SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   }

   double slPrice    = SL_ticks * _Point;
   double lossPerLot = (slPrice / tickSize) * tickValue;

   if(lossPerLot <= 0)
   {
      Print("CTR: lossPerLot=0 — using min lot");
      return SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   }

   double lots = riskAmount / lossPerLot;

   if(DebugMode)
      Print("CTR: LotCalc | Balance=", DoubleToString(balance, 2),
            " | Risk$=", DoubleToString(riskAmount, 2),
            " | LossPerLot=", DoubleToString(lossPerLot, 2),
            " | Raw lots=", DoubleToString(lots, 4));

   return NormalizeLots(lots);
}

double NormalizeLots(double lots)
{
   double minL = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxL = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double step = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   if(step <= 0) step = 0.01;

   lots = MathFloor(lots / step) * step;
   lots = MathMax(lots, minL);
   lots = MathMin(lots, maxL);
   return NormalizeDouble(lots, 2);
}

//+------------------------------------------------------------------+
//| POSITION MANAGEMENT                                               |
//+------------------------------------------------------------------+
void ManageOpenPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i))      continue;
      if(m_pos.Magic() != MagicNumber) continue;
      if(m_pos.Symbol() != _Symbol)    continue;

      double entry = m_pos.PriceOpen();
      double curSL = m_pos.StopLoss();
      double curTP = m_pos.TakeProfit();
      ulong  tkt   = m_pos.Ticket();

      if(m_pos.PositionType() == POSITION_TYPE_BUY)
      {
         double bid = SymbolInfoDouble(_Symbol, SYMBOL_BID);
         double prof = (bid - entry) / _Point;

         if(EnableBreakeven && prof >= BE_TriggerTicks)
         {
            double newSL = NormalizeDouble(entry + BE_OffsetTicks * _Point, _Digits);
            if(curSL < newSL)
               m_trade.PositionModify(tkt, newSL, curTP);
         }
         if(EnablePartials && !g_partialDone && prof >= PartialTrigTicks)
         {
            double cl = NormalizeLots(m_pos.Volume() * PartialPercent / 100.0);
            if(cl > 0 && cl < m_pos.Volume())
            { m_trade.PositionClosePartial(tkt, cl); g_partialDone = true; }
         }
      }
      else
      {
         double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
         double prof = (entry - ask) / _Point;

         if(EnableBreakeven && prof >= BE_TriggerTicks)
         {
            double newSL = NormalizeDouble(entry - BE_OffsetTicks * _Point, _Digits);
            if(curSL > newSL || curSL == 0)
               m_trade.PositionModify(tkt, newSL, curTP);
         }
         if(EnablePartials && !g_partialDone && prof >= PartialTrigTicks)
         {
            double cl = NormalizeLots(m_pos.Volume() * PartialPercent / 100.0);
            if(cl > 0 && cl < m_pos.Volume())
            { m_trade.PositionClosePartial(tkt, cl); g_partialDone = true; }
         }
      }
   }
}

//+------------------------------------------------------------------+
//| TIME HELPERS                                                      |
//+------------------------------------------------------------------+
bool IsNewBar()
{
   datetime t = iTime(_Symbol, _Period, 0);
   if(t == g_lastBarTime) return false;
   g_lastBarTime = t;
   return true;
}

void CheckDayReset()
{
   MqlDateTime dt;
   TimeCurrent(dt);
   datetime today = StringToTime(StringFormat("%d.%02d.%02d", dt.year, dt.mon, dt.day));

   if(today != g_currentDay)
   {
      g_currentDay       = today;
      g_candleMarked     = false;
      g_keyHigh          = 0;
      g_keyLow           = 0;
      g_keyCandleTime    = 0;
      g_barsSinceKey     = 0;
      g_signalFiredToday = false;
      g_tradesToday      = 0;
      g_partialDone      = false;

      if(DebugMode)
         Print("── New day: ", TimeToString(today, TIME_DATE), " ──");
   }
}

bool IsTradingDay()
{
   MqlDateTime dt;
   TimeCurrent(dt);
   switch(dt.day_of_week)
   {
      case 0: return TradeSunday;
      case 1: return TradeMonday;
      case 2: return TradeTuesday;
      case 3: return TradeWednesday;
      case 4: return TradeThursday;
      case 5: return TradeFriday;
      case 6: return TradeSaturday;
   }
   return false;
}

//+------------------------------------------------------------------+
//| POSITION HELPERS                                                  |
//+------------------------------------------------------------------+
bool HasOpenPosition()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         return true;
   }
   return false;
}

int CountTradesToday()
{
   int count = 0;
   datetime sod = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));

   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         if(m_pos.Time() >= sod) count++;
   }

   HistorySelect(sod, sod + 86400);
   for(int i = HistoryDealsTotal() - 1; i >= 0; i--)
   {
      ulong tk = HistoryDealGetTicket(i);
      if(tk == 0) continue;
      if(HistoryDealGetInteger(tk, DEAL_MAGIC) == MagicNumber &&
         HistoryDealGetString(tk, DEAL_SYMBOL) == _Symbol &&
         HistoryDealGetInteger(tk, DEAL_ENTRY) == DEAL_ENTRY_IN)
         count++;
   }
   return count;
}

double GetDailyPnL()
{
   double pnl = 0;
   datetime sod = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));

   HistorySelect(sod, sod + 86400);
   for(int i = HistoryDealsTotal() - 1; i >= 0; i--)
   {
      ulong tk = HistoryDealGetTicket(i);
      if(tk == 0) continue;
      if(HistoryDealGetInteger(tk, DEAL_MAGIC) == MagicNumber &&
         HistoryDealGetString(tk, DEAL_SYMBOL) == _Symbol &&
         HistoryDealGetInteger(tk, DEAL_ENTRY) == DEAL_ENTRY_OUT)
         pnl += HistoryDealGetDouble(tk, DEAL_PROFIT)
              + HistoryDealGetDouble(tk, DEAL_SWAP)
              + HistoryDealGetDouble(tk, DEAL_COMMISSION);
   }

   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         pnl += m_pos.Profit() + m_pos.Swap() + m_pos.Commission();
   }
   return pnl;
}

void CloseAllPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         m_trade.PositionClose(m_pos.Ticket());
   }
}

void CloseWinningPositions()
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic() == MagicNumber && m_pos.Symbol() == _Symbol)
         if(m_pos.Profit() > 0)
            m_trade.PositionClose(m_pos.Ticket());
   }
}

