void UpdateDashboard()
{
   if(!ShowDashboard) return;

   string st; color cs;
   if(!IsTradingDay())           {st="Day Off";       cs=clrDarkGray;}
   else if(g_signalFiredToday)   {st="Done";          cs=clrOrange;}
   else if(!g_candleMarked)      {st="Wait candle";   cs=clrYellow;}
   else if(HasOpenPosition())    {st="In Trade";      cs=clrDodgerBlue;}
   else                          {st="Scanning";      cs=clrLime;}
   SetLbl(DP+"V1",st,cs);

   long sp=SymbolInfoInteger(_Symbol,SYMBOL_SPREAD);
   SetLbl(DP+"V2",IntegerToString(sp)+" pts",sp>MaxSpreadPoints?clrRed:clrWhite);

   double pnl=GetDailyPnL();
   SetLbl(DP+"V3",(pnl>=0?"+$":"-$")+DoubleToString(MathAbs(pnl),2),pnl>=0?clrLime:clrRed);
   SetLbl(DP+"V4",IntegerToString(g_tradesToday)+"/"+IntegerToString(MaxTradesPerDay),clrWhite);

   if(g_candleMarked)
   {
      SetLbl(DP+"V6",DoubleToString(g_keyHigh,_Digits),ColorHigh);
      SetLbl(DP+"V7",DoubleToString(g_keyLow,_Digits),ColorLow);
      SetLbl(DP+"V8",IntegerToString(g_barsSinceKey)+"/"+IntegerToString(WindowBars),clrWhite);
   }
   else
   {
      SetLbl(DP+"V6","---",clrDarkGray);
      SetLbl(DP+"V7","---",clrDarkGray);
      SetLbl(DP+"V8","-",clrDarkGray);
   }

   if(g_signalFiredToday) SetLbl(DP+"V9","Done today",clrOrange);
   else if(g_candleMarked) SetLbl(DP+"V9","Watching...",clrYellow);
   else SetLbl(DP+"V9","No candle yet",clrDarkGray);
}

