void OnChartEvent(const int id, const long &lparam,
                  const double &dparam, const string &sparam)
{
   if(id != CHARTEVENT_OBJECT_CLICK) return;
   if(sparam == DP + "BtnCloseAll")
   { CloseAllPositions(); ObjectSetInteger(0, sparam, OBJPROP_STATE, false); }
   else if(sparam == DP + "BtnCloseWin")
   { CloseWinningPositions(); ObjectSetInteger(0, sparam, OBJPROP_STATE, false); }
   else if(sparam == DP + "BtnPause")
   { g_signalFiredToday = !g_signalFiredToday; ObjectSetInteger(0, sparam, OBJPROP_STATE, false); }
}

