void ExecuteBuy(double sweepLow, double reclaimClose)
{
   double ask = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double sl  = NormalizeDouble(ask - SL_ticks * _Point, _Digits);
   double tp  = NormalizeDouble(ask + TP_ticks * _Point, _Digits);
   double lots = CalculateLotSize();

   if(lots <= 0)
   {
      Print("CTR: Lot size = 0, cannot trade");
      LogCSV("SIGNAL_BUY_SKIP", "BUY", ask, sl, tp, 0, "LotSize=0");
      return;
   }

   Print("CTR: Sending BUY | Ask=", DoubleToString(ask, _Digits),
         " | SL=", DoubleToString(sl, _Digits),
         " | TP=", DoubleToString(tp, _Digits),
         " | Lots=", DoubleToString(lots, 2));

   if(m_trade.Buy(lots, _Symbol, ask, sl, tp, "CTR BUY"))
   {
      g_signalFiredToday = true;
      g_partialDone      = false;
      Print("✓ CTR BUY FILLED | Ticket=", m_trade.ResultOrder());
      LogCSV("BUY_FILLED", "BUY", ask, sl, tp, lots, "OK");
   }
   else
   {
      int errCode = (int)m_trade.ResultRetcode();
      string errMsg = m_trade.ResultRetcodeDescription();
      Print("✗ CTR BUY FAILED: code=", errCode, " | ", errMsg);
      LogCSV("BUY_FAILED", "BUY", ask, sl, tp, lots,
             "code=" + IntegerToString(errCode) + " " + errMsg);

      // ── RETRY: not enough money → try min lot ──
      if(errCode == TRADE_RETCODE_NO_MONEY)
      {
         double minLot = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
         Print("CTR: Retrying with min lot=", DoubleToString(minLot, 2));
         if(m_trade.Buy(minLot, _Symbol, ask, sl, tp, "CTR BUY min"))
         {
            g_signalFiredToday = true;
            g_partialDone      = false;
            Print("✓ CTR BUY FILLED (min lot) | Ticket=", m_trade.ResultOrder());
            LogCSV("BUY_FILLED_MINLOT", "BUY", ask, sl, tp, minLot, "OK_minlot");
         }
         else
         {
            Print("✗ CTR BUY MIN LOT FAILED: ", m_trade.ResultRetcodeDescription());
            LogCSV("BUY_MINLOT_FAILED", "BUY", ask, sl, tp, minLot,
                   m_trade.ResultRetcodeDescription());
         }
      }
      // ── RETRY: invalid stops → send without SL/TP then modify ──
      else if(errCode == TRADE_RETCODE_INVALID_STOPS)
