void LogCSV(string event, string dir, double price, double sl, double tp,
            double lots, string result)
{
   if(!ExportCSV || g_csvHandle == INVALID_HANDLE) return;

   MqlDateTime dt;
   TimeCurrent(dt);
   string dayNames[] = {"Sun","Mon","Tue","Wed","Thu","Fri","Sat"};

   double balance    = m_account.Balance();
   double riskAmount = balance * RiskPercent / 100.0;
   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   double lossPerLot = 0;
   if(tickSize > 0) lossPerLot = (SL_ticks * _Point / tickSize) * tickValue;

   double marginReq  = 0;
   if(lots > 0)
      OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, price, marginReq);

   long spread = SymbolInfoInteger(_Symbol, SYMBOL_SPREAD);

   // Sweep bar data
   double bO = iOpen(_Symbol, _Period, 1);
   double bH = iHigh(_Symbol, _Period, 1);
   double bL = iLow(_Symbol, _Period, 1);
   double bC = iClose(_Symbol, _Period, 1);

   double keyRange = (g_keyHigh > 0 && g_keyLow > 0) ?
                     (g_keyHigh - g_keyLow) / _Point : 0;

   FileWrite(g_csvHandle,
      TimeToString(TimeCurrent(), TIME_DATE),        // Date
      TimeToString(TimeCurrent(), TIME_MINUTES),     // Time
      dayNames[dt.day_of_week],                      // DayOfWeek
      event,                                         // Event
      dir,                                           // Direction
      (g_keyCandleTime > 0 ? TimeToString(g_keyCandleTime, TIME_MINUTES) : ""),
      DoubleToString(g_keyHigh, _Digits),            // KeyHigh
      DoubleToString(g_keyLow, _Digits),             // KeyLow
      DoubleToString(keyRange, 0),                    // KeyRange_ticks
      DoubleToString(bO, _Digits),                   // SweepBar OHLC
      DoubleToString(bH, _Digits),
      DoubleToString(bL, _Digits),
      DoubleToString(bC, _Digits),
      DoubleToString(price, _Digits),                // Entry
