//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   if(g_csvHandle != INVALID_HANDLE) FileClose(g_csvHandle);
   ObjectsDeleteAll(0, DP);
   Comment("");
}

//+------------------------------------------------------------------+
void ComputeServerTime(int gmtOffset)
{
   // NY is UTC-5 winter / UTC-4 summer
   // Server hour = NY_Hour + 5 (to UTC) + gmtOffset
   g_serverHour   = NY_Hour + 5 + gmtOffset;
   g_serverMinute = NY_Minute;
   if(g_serverHour >= 24) g_serverHour -= 24;
   if(g_serverHour < 0)   g_serverHour += 24;

   // Snap minute to valid bar open for this timeframe
   int tfMin = PeriodSeconds(_Period) / 60;
   if(tfMin > 0 && (g_serverMinute % tfMin) != 0)
   {
      int snapped = (g_serverMinute / tfMin) * tfMin;
      if(DebugMode)
         Print("CTR: Minute ", g_serverMinute, " snapped to ", snapped, " for ", EnumToString(_Period));
      g_serverMinute = snapped;
   }
}

//+------------------------------------------------------------------+
//| Detect DST by checking if recent bars exist at expected hour      |
//| Try winter offset first, if no bar found try summer offset        |
//+------------------------------------------------------------------+
void AutoDetectDST()
{
   if(!AutoDST) return;

   // Check: does a bar exist at the winter-offset hour today?
   int winterHour = NY_Hour + 5 + BrokerGMT_Winter;
   int summerHour = NY_Hour + 5 + BrokerGMT_Summer;
   if(winterHour >= 24) winterHour -= 24;
   if(summerHour >= 24) summerHour -= 24;

   int tfMin = PeriodSeconds(_Period) / 60;
   int snapMin = NY_Minute;
   if(tfMin > 0 && (snapMin % tfMin) != 0)
      snapMin = (snapMin / tfMin) * tfMin;

   datetime todayStart = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));

   // Scan today's bars for winter hour match
   bool foundWinter = false, foundSummer = false;
   int totalBars = Bars(_Symbol, _Period);

   for(int i = 0; i < MathMin(totalBars, 200); i++)
   {
      datetime bt = iTime(_Symbol, _Period, i);
      if(bt < todayStart) break;

      MqlDateTime dt;
      TimeToStruct(bt, dt);

      if(dt.hour == winterHour && dt.min == snapMin) foundWinter = true;
      if(dt.hour == summerHour && dt.min == snapMin) foundSummer = true;
   }

   // If today's bars don't exist yet (pre-market), check yesterday
   if(!foundWinter && !foundSummer)
   {
      datetime yesterStart = todayStart - 86400;
      for(int i = 0; i < MathMin(totalBars, 300); i++)
      {
         datetime bt = iTime(_Symbol, _Period, i);
         if(bt < yesterStart) break;
         if(bt >= todayStart) continue;

         MqlDateTime dt;
         TimeToStruct(bt, dt);
         if(dt.hour == winterHour && dt.min == snapMin) foundWinter = true;
         if(dt.hour == summerHour && dt.min == snapMin) foundSummer = true;
      }
   }

   int newOffset = BrokerGMT_Winter;
   if(foundWinter)       newOffset = BrokerGMT_Winter;
   else if(foundSummer)  newOffset = BrokerGMT_Summer;

   int prevHour = g_serverHour;
   ComputeServerTime(newOffset);

   if(g_serverHour != prevHour && DebugMode)
      Print("CTR: DST switch detected → Server hour changed from ", prevHour, " to ", g_serverHour,
            " (GMT+", newOffset, ")");
}

//+------------------------------------------------------------------+
//| TICK                                                              |
//+------------------------------------------------------------------+
void OnTick()
{
   if(ShowDashboard) UpdateDashboard();
   ManageOpenPositions();

   if(!IsNewBar()) return;

   CheckDayReset();
   g_tradesToday = CountTradesToday();

   if(!IsTradingDay()) return;

   // ── STEP 1: Find key candle ──
   if(!g_candleMarked && !g_signalFiredToday)
      ScanForKeyCandle();

   if(!g_candleMarked) return;

   // ── STEP 2: Bars since key candle ──
   int barsSince = BarsSinceKeyCandle();
   g_barsSinceKey = barsSince;

   if(barsSince < 1 || barsSince > WindowBars) return;

   // ── Guards ──
   if(g_signalFiredToday)              return;
   if(g_tradesToday >= MaxTradesPerDay) return;
   if(HasOpenPosition())               return;

   long spread = SymbolInfoInteger(_Symbol, SYMBOL_SPREAD);
   if(spread > MaxSpreadPoints) return;

   // ── STEP 3: Check ALL bars from key+1 to current-1 for sweep ──
   // This fixes the bug where sweeps on older bars were missed
   int startCheck = MathMax(1, barsSince);  // oldest unchecked
   for(int b = startCheck; b >= 1; b--)
   {
      double bH = iHigh(_Symbol, _Period, b);
      double bL = iLow(_Symbol, _Period, b);
      double bC = iClose(_Symbol, _Period, b);

      // ═══ BULLISH: swept low + closed above ═══
      if(TradeType != DIR_Sell && bL < g_keyLow && bC > g_keyLow)
      {
         if(DebugMode)
            Print("✓ BULL SWEEP bar[", b, "] L=", DoubleToString(bL,_Digits),
                  " < KeyLow=", DoubleToString(g_keyLow,_Digits),
                  " C=", DoubleToString(bC,_Digits));
         ExecuteTrade(ORDER_TYPE_BUY, bL, bC);
         return;
      }

      // ═══ BEARISH: swept high + closed below ═══
      if(TradeType != DIR_Buy && bH > g_keyHigh && bC < g_keyHigh)
      {
         if(DebugMode)
            Print("✓ BEAR SWEEP bar[", b, "] H=", DoubleToString(bH,_Digits),
                  " > KeyHigh=", DoubleToString(g_keyHigh,_Digits),
                  " C=", DoubleToString(bC,_Digits));
         ExecuteTrade(ORDER_TYPE_SELL, bH, bC);
         return;
      }
   }
}

//+------------------------------------------------------------------+
//| SCAN FOR KEY CANDLE — robust version                              |
//+------------------------------------------------------------------+
void ScanForKeyCandle()
{
   // Run DST auto-detect once per day
   AutoDetectDST();

   datetime todayStart = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));
   int totalBars = Bars(_Symbol, _Period);
   bool foundAnyBar = false;

   for(int i = 1; i < MathMin(totalBars, 500); i++)
   {
      datetime bt = iTime(_Symbol, _Period, i);
      if(bt == 0) continue;  // invalid bar
      if(bt < todayStart) break;

      foundAnyBar = true;
      MqlDateTime dt;
      TimeToStruct(bt, dt);

      if(dt.hour == g_serverHour && dt.min == g_serverMinute)
      {
         double hi = iHigh(_Symbol, _Period, i);
         double lo = iLow(_Symbol, _Period, i);

         if(hi == 0 || lo == 0 || hi == lo)
         {
            if(DebugMode)
               Print("CTR: Key candle at bar[", i, "] has invalid OHLC. Skip.");
            return;
         }

         int keyRange = (int)((hi - lo) / _Point);

         // Range filter
         if(MaxKeyRange > 0 && keyRange > MaxKeyRange)
         {
            g_signalFiredToday = true;
            LogCSV("KEY_RANGE_TOO_WIDE","",0,0,0,0,
                   "Range="+IntegerToString(keyRange)+" Max="+IntegerToString(MaxKeyRange));
            return;
         }
         if(MinKeyRange > 0 && keyRange < MinKeyRange)
         {
            g_signalFiredToday = true;
            LogCSV("KEY_RANGE_TOO_NARROW","",0,0,0,0,
                   "Range="+IntegerToString(keyRange)+" Min="+IntegerToString(MinKeyRange));
            return;
         }

         g_keyHigh       = hi;
         g_keyLow        = lo;
         g_keyCandleTime = bt;
         g_keyCandleShift = i;
         g_candleMarked  = true;

         if(DrawLevels)
         {
            string sfx = TimeToString(bt, TIME_DATE);
            DrawHLine(DP+"H_"+sfx, hi, ColorHigh, "CTR H");
            DrawHLine(DP+"L_"+sfx, lo, ColorLow, "CTR L");
         }

         if(DebugMode)
            Print("✦ Key candle bar[", i, "] ", TimeToString(bt),
                  " H=", DoubleToString(hi,_Digits),
                  " L=", DoubleToString(lo,_Digits),
                  " Range=", keyRange);
         return;
      }
   }

   // Diagnostic: why wasn't it found?
   if(!foundAnyBar)
   {
      if(DebugMode) Print("CTR: No bars found for today. Data gap?");
   }
   else
   {
      // Log once per day only
      static datetime lastLogDay = 0;
      if(todayStart != lastLogDay)
      {
         lastLogDay = todayStart;
         MqlDateTime nowDt; TimeCurrent(nowDt);
         if(DebugMode)
            Print("CTR: Key candle NOT FOUND today. Looking for ",
                  StringFormat("%02d:%02d", g_serverHour, g_serverMinute),
                  " | Now=", StringFormat("%02d:%02d", nowDt.hour, nowDt.min),
                  " | Bars today=", totalBars > 500 ? 500 : totalBars);
      }
   }
}

//+------------------------------------------------------------------+
int BarsSinceKeyCandle()
{
   if(!g_candleMarked || g_keyCandleTime == 0) return 999;

   // More robust than iBarShift: count bars manually
   int total = Bars(_Symbol, _Period);
   for(int i = 0; i < MathMin(total, 200); i++)
   {
      datetime bt = iTime(_Symbol, _Period, i);
      if(bt == g_keyCandleTime) return i;
      if(bt < g_keyCandleTime) return i;  // passed it
   }
   return 999;
}

//+------------------------------------------------------------------+
//| UNIFIED TRADE EXECUTION                                           |
//+------------------------------------------------------------------+
void ExecuteTrade(ENUM_ORDER_TYPE type, double sweepPrice, double reclaimClose)
{
   bool isBuy = (type == ORDER_TYPE_BUY);
   double price = isBuy ? SymbolInfoDouble(_Symbol, SYMBOL_ASK)
                        : SymbolInfoDouble(_Symbol, SYMBOL_BID);
   double sl = isBuy ? NormalizeDouble(price - SL_ticks * _Point, _Digits)
                     : NormalizeDouble(price + SL_ticks * _Point, _Digits);
   double tp = isBuy ? NormalizeDouble(price + TP_ticks * _Point, _Digits)
                     : NormalizeDouble(price - TP_ticks * _Point, _Digits);
   string dir = isBuy ? "BUY" : "SELL";

   double lots = CalcLots();
   if(lots <= 0)
   {
      Print("CTR: Lots=0, cannot trade");
      LogCSV("SIGNAL_"+dir+"_SKIP", dir, price, sl, tp, 0, "Lots=0");
      return;
   }

   Print("CTR: ", dir, " | Price=", DoubleToString(price,_Digits),
         " SL=", DoubleToString(sl,_Digits), " TP=", DoubleToString(tp,_Digits),
         " Lots=", DoubleToString(lots,2));

   bool ok = isBuy ? m_trade.Buy(lots, _Symbol, price, sl, tp, "CTR "+dir)
                   : m_trade.Sell(lots, _Symbol, price, sl, tp, "CTR "+dir);

   if(ok)
   {
      g_signalFiredToday = true;
      g_partialDone = false;
      Print("✓ CTR ", dir, " FILLED | Ticket=", m_trade.ResultOrder());
      LogCSV(dir+"_FILLED", dir, price, sl, tp, lots, "OK");
   }
   else
   {
      int err = (int)m_trade.ResultRetcode();
      string errMsg = m_trade.ResultRetcodeDescription();
      Print("✗ CTR ", dir, " FAILED: ", err, " ", errMsg);
      LogCSV(dir+"_FAILED", dir, price, sl, tp, lots,
             IntegerToString(err)+" "+errMsg);

      // Retry: not enough money → min lot
      if(err == TRADE_RETCODE_NO_MONEY)
      {
         double minL = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
         ok = isBuy ? m_trade.Buy(minL, _Symbol, price, sl, tp, "CTR "+dir+" min")
                    : m_trade.Sell(minL, _Symbol, price, sl, tp, "CTR "+dir+" min");
         if(ok)
         {
            g_signalFiredToday = true;
            LogCSV(dir+"_FILLED_MINLOT", dir, price, sl, tp, minL, "OK_minlot");
         }
      }
      // Retry: invalid stops → send naked, modify after
      else if(err == TRADE_RETCODE_INVALID_STOPS)
      {
         ok = isBuy ? m_trade.Buy(lots, _Symbol, price, 0, 0, "CTR "+dir)
                    : m_trade.Sell(lots, _Symbol, price, 0, 0, "CTR "+dir);
         if(ok)
         {
            g_signalFiredToday = true;
            ulong tkt = m_trade.ResultOrder();
            if(tkt > 0) m_trade.PositionModify(tkt, sl, tp);
            LogCSV(dir+"_FILLED_RETRY", dir, price, sl, tp, lots, "OK_nostops");
         }
      }
   }
}

//+------------------------------------------------------------------+
//| LOT SIZE — supports fixed $, %, or fixed lots                     |
//+------------------------------------------------------------------+
double CalcLots()
{
   double minL = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxL = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double step = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   if(step <= 0) step = 0.01;

   double lots = minL;

   if(RiskMode == RISK_FIXED_LOTS)
   {
      lots = FixedLots;
   }
   else
   {
      double riskAmount;
      if(RiskMode == RISK_FIXED_USD)
         riskAmount = RiskDollars;
      else
         riskAmount = m_account.Balance() * RiskPercent / 100.0;

      double tickVal  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
      double tickSize = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);

      if(tickVal <= 0 || tickSize <= 0)
      {
         Print("CTR: Invalid tickVal=", tickVal, " tickSize=", tickSize);
         return minL;
      }

      double slPrice    = SL_ticks * _Point;
      double lossPerLot = (slPrice / tickSize) * tickVal;

      if(lossPerLot <= 0) return minL;

      lots = riskAmount / lossPerLot;

      if(DebugMode)
         Print("CTR: LotCalc | Risk$=", DoubleToString(riskAmount,2),
               " | LossPerLot=", DoubleToString(lossPerLot,2),
               " | Raw=", DoubleToString(lots,4));
   }

   // Normalize
   lots = MathFloor(lots / step) * step;
   lots = MathMax(lots, minL);
   lots = MathMin(lots, maxL);

   // Margin check
   double price = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double marginReq = 0;
   if(OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, price, marginReq))
   {
      double freeMargin = m_account.FreeMargin();
      if(marginReq > freeMargin * 0.9)
      {
         double safeLots = lots * (freeMargin * 0.9) / marginReq;
         safeLots = MathFloor(safeLots / step) * step;
         safeLots = MathMax(safeLots, minL);
         if(DebugMode)
            Print("CTR: Margin cap | ", DoubleToString(lots,2), " → ",
                  DoubleToString(safeLots,2), " (margin=", DoubleToString(marginReq,2),
                  " free=", DoubleToString(freeMargin,2), ")");
         lots = safeLots;

         // Final check
         OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, price, marginReq);
         if(marginReq > freeMargin)
         {
            Print("CTR: Still no margin for min lot. Cannot trade.");
            return 0;
         }
      }
   }

   return NormalizeDouble(lots, 2);
}

//+------------------------------------------------------------------+
//| POSITION MANAGEMENT                                               |
//+------------------------------------------------------------------+
void ManageOpenPositions()
{
   for(int i = PositionsTotal()-1; i >= 0; i--)
   {
      if(!m_pos.SelectByIndex(i)) continue;
      if(m_pos.Magic()!=MagicNumber || m_pos.Symbol()!=_Symbol) continue;

      double entry=m_pos.PriceOpen(), curSL=m_pos.StopLoss(), curTP=m_pos.TakeProfit();
      ulong tkt=m_pos.Ticket();
      bool isBuy = m_pos.PositionType()==POSITION_TYPE_BUY;
      double curPrice = isBuy ? SymbolInfoDouble(_Symbol,SYMBOL_BID) : SymbolInfoDouble(_Symbol,SYMBOL_ASK);
      double profTicks = isBuy ? (curPrice-entry)/_Point : (entry-curPrice)/_Point;

      if(EnableBreakeven && profTicks >= BE_TriggerTicks)
      {
         double newSL = isBuy ? NormalizeDouble(entry+BE_OffsetTicks*_Point,_Digits)
                              : NormalizeDouble(entry-BE_OffsetTicks*_Point,_Digits);
         bool shouldModify = isBuy ? (curSL < newSL) : (curSL > newSL || curSL == 0);
         if(shouldModify) m_trade.PositionModify(tkt, newSL, curTP);
      }
   }
}

