//+------------------------------------------------------------------+
bool IsNewBar()
{
   datetime t = iTime(_Symbol, _Period, 0);
   if(t == g_lastBarTime) return false;
   g_lastBarTime = t;
   return true;
}

void CheckDayReset()
{
   MqlDateTime dt;
   TimeCurrent(dt);
   datetime today = StringToTime(StringFormat("%04d.%02d.%02d", dt.year, dt.mon, dt.day));

   if(today != g_currentDay)
   {
      g_currentDay       = today;
      g_candleMarked     = false;
      g_keyHigh          = 0; g_keyLow = 0;
      g_keyCandleTime    = 0; g_keyCandleShift = -1;
      g_signalFiredToday = false;
      g_tradesToday      = 0;
      g_partialDone      = false;
   }
}

bool IsTradingDay()
{
   MqlDateTime dt; TimeCurrent(dt);
   switch(dt.day_of_week)
   {
      case 0: return TradeSunday;    case 1: return TradeMonday;
      case 2: return TradeTuesday;   case 3: return TradeWednesday;
      case 4: return TradeThursday;  case 5: return TradeFriday;
      case 6: return TradeSaturday;
   }
   return false;
}

bool HasOpenPosition()
{
   for(int i=PositionsTotal()-1;i>=0;i--)
   { if(!m_pos.SelectByIndex(i)) continue;
     if(m_pos.Magic()==MagicNumber && m_pos.Symbol()==_Symbol) return true; }
   return false;
}

int CountTradesToday()
{
   int count=0;
   datetime sod = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));

   for(int i=PositionsTotal()-1;i>=0;i--)
   { if(!m_pos.SelectByIndex(i)) continue;
     if(m_pos.Magic()==MagicNumber && m_pos.Symbol()==_Symbol && m_pos.Time()>=sod) count++; }

   HistorySelect(sod, sod+86400);
   for(int i=HistoryDealsTotal()-1;i>=0;i--)
   { ulong tk=HistoryDealGetTicket(i); if(tk==0) continue;
     if(HistoryDealGetInteger(tk,DEAL_MAGIC)==MagicNumber &&
        HistoryDealGetString(tk,DEAL_SYMBOL)==_Symbol &&
        HistoryDealGetInteger(tk,DEAL_ENTRY)==DEAL_ENTRY_IN) count++; }
   return count;
}

double GetDailyPnL()
{
   double pnl=0;
   datetime sod=StringToTime(TimeToString(TimeCurrent(),TIME_DATE));
   HistorySelect(sod,sod+86400);
   for(int i=HistoryDealsTotal()-1;i>=0;i--)
   { ulong tk=HistoryDealGetTicket(i); if(tk==0) continue;
     if(HistoryDealGetInteger(tk,DEAL_MAGIC)==MagicNumber &&
        HistoryDealGetString(tk,DEAL_SYMBOL)==_Symbol &&
        HistoryDealGetInteger(tk,DEAL_ENTRY)==DEAL_ENTRY_OUT)
        pnl += HistoryDealGetDouble(tk,DEAL_PROFIT)+HistoryDealGetDouble(tk,DEAL_SWAP)+HistoryDealGetDouble(tk,DEAL_COMMISSION); }
   for(int i=PositionsTotal()-1;i>=0;i--)
   { if(!m_pos.SelectByIndex(i)) continue;
     if(m_pos.Magic()==MagicNumber && m_pos.Symbol()==_Symbol)
        pnl += m_pos.Profit()+m_pos.Swap()+m_pos.Commission(); }
   return pnl;
}

//+------------------------------------------------------------------+
//| CSV LOG                                                           |
//+------------------------------------------------------------------+
void LogCSV(string event,string dir,double price,double sl,double tp,double lots,string result)
{
   if(!ExportCSV || g_csvHandle==INVALID_HANDLE) return;
   MqlDateTime dt; TimeCurrent(dt);
   string days[]={"Sun","Mon","Tue","Wed","Thu","Fri","Sat"};
   double bal=m_account.Balance();
   double riskAmt = RiskMode==RISK_FIXED_USD ? RiskDollars : bal*RiskPercent/100.0;
   double tickV=SymbolInfoDouble(_Symbol,SYMBOL_TRADE_TICK_VALUE);
   double tickS=SymbolInfoDouble(_Symbol,SYMBOL_TRADE_TICK_SIZE);
   double lpl=0; if(tickS>0) lpl=(SL_ticks*_Point/tickS)*tickV;
   double mreq=0; if(lots>0) OrderCalcMargin(ORDER_TYPE_BUY,_Symbol,lots,price,mreq);
   long sp=SymbolInfoInteger(_Symbol,SYMBOL_SPREAD);
   double bO=iOpen(_Symbol,_Period,1),bH=iHigh(_Symbol,_Period,1),bL=iLow(_Symbol,_Period,1),bC=iClose(_Symbol,_Period,1);
   double kr=(g_keyHigh>0&&g_keyLow>0)?(g_keyHigh-g_keyLow)/_Point:0;

   FileWrite(g_csvHandle,
      TimeToString(TimeCurrent(),TIME_DATE),TimeToString(TimeCurrent(),TIME_MINUTES),
      days[dt.day_of_week],event,dir,
      g_keyCandleTime>0?TimeToString(g_keyCandleTime,TIME_MINUTES):"",
      DoubleToString(g_keyHigh,_Digits),DoubleToString(g_keyLow,_Digits),DoubleToString(kr,0),
      DoubleToString(bO,_Digits),DoubleToString(bH,_Digits),DoubleToString(bL,_Digits),DoubleToString(bC,_Digits),
      DoubleToString(price,_Digits),DoubleToString(sl,_Digits),DoubleToString(tp,_Digits),DoubleToString(lots,2),
      DoubleToString(bal,2),DoubleToString(riskAmt,2),DoubleToString(lpl,2),DoubleToString(mreq,2),
      IntegerToString(sp),IntegerToString(g_barsSinceKey),IntegerToString(g_serverHour),result,"","");
   FileFlush(g_csvHandle);
}

