void UpdateDashboard()
{
   if(!ShowDashboard) return;
   string st;color cs;
   if(!IsTradingDay()){st="Day Off";cs=clrDarkGray;}
   else if(g_signalFiredToday){st="Done";cs=clrOrange;}
   else if(!g_candleMarked){st="Wait key";cs=clrYellow;}
   else if(HasOpenPosition()){st="In Trade";cs=clrDodgerBlue;}
   else{st="Scanning";cs=clrLime;}
   SLbl(DP+"V1",st,cs);
   long sp=SymbolInfoInteger(_Symbol,SYMBOL_SPREAD);
   SLbl(DP+"V2",IntegerToString(sp)+"pts",sp>MaxSpreadPoints?clrRed:clrWhite);
   double pnl=GetDailyPnL();
   SLbl(DP+"V3",(pnl>=0?"+$":"-$")+DoubleToString(MathAbs(pnl),2),pnl>=0?clrLime:clrRed);
   SLbl(DP+"V4",IntegerToString(g_tradesToday)+"/"+IntegerToString(MaxTradesPerDay),clrWhite);
   if(g_candleMarked){SLbl(DP+"V5",DoubleToString(g_keyHigh,_Digits),ColorHigh);SLbl(DP+"V6",DoubleToString(g_keyLow,_Digits),ColorLow);}
   else{SLbl(DP+"V5","---",clrDarkGray);SLbl(DP+"V6","---",clrDarkGray);}
   SLbl(DP+"V7",StringFormat("%02d:%02d",g_serverHour,g_serverMinute),clrDodgerBlue);
   if(g_signalFiredToday) SLbl(DP+"V9","Done",clrOrange);
   else if(g_candleMarked) SLbl(DP+"V9","Watching...",clrYellow);
   else SLbl(DP+"V9","No key yet",clrDarkGray);
}

