             "code=" + IntegerToString(errCode) + " " + errMsg);

      if(errCode == TRADE_RETCODE_NO_MONEY)
      {
         double minLot = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
         Print("CTR: Retrying with min lot=", DoubleToString(minLot, 2));
