//| LOT SIZE — Uses OrderCalcProfit for 100% accuracy on any symbol   |
//+------------------------------------------------------------------+
double CalculateLotSize()
{
   double minLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot  = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_STEP);
   if(lotStep <= 0) lotStep = 0.01;

   // ── FIXED LOTS ──
   if(RiskMode == RISK_FIXED_LOTS)
      return NormalizeLots(FixedLots);

   // ── Calculate risk amount ──
   double riskAmount;
   if(RiskMode == RISK_FIXED_USD)
      riskAmount = RiskDollars;
   else
      riskAmount = m_account.Balance() * RiskPercent / 100.0;

   // ── Use OrderCalcProfit to find exact loss per 1 lot ──
   // This accounts for ContractSize, TickValue, currency conversion — everything
   double price = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
   double slPrice = price - SL_ticks * _Point;  // simulate BUY hitting SL
   double lossFor1Lot = 0;

   if(!OrderCalcProfit(ORDER_TYPE_BUY, _Symbol, 1.0, price, slPrice, lossFor1Lot))
   {
      Print("CTR: OrderCalcProfit failed! Using fallback formula.");
      // Fallback: manual formula
      double tickVal = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
      double tickSz  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
      if(tickVal > 0 && tickSz > 0)
         lossFor1Lot = -((SL_ticks * _Point) / tickSz) * tickVal;
      else
         return minLot;
   }

   // lossFor1Lot will be NEGATIVE (it's a loss)
   double absLoss = MathAbs(lossFor1Lot);

   if(absLoss <= 0)
   {
      Print("CTR: Loss per lot = 0. Using min lot.");
      return minLot;
   }

   double lots = riskAmount / absLoss;

   if(DebugMode)
      Print("CTR: LotCalc | Mode=", EnumToString(RiskMode),
            " | Risk$=", DoubleToString(riskAmount, 2),
            " | LossPerLot=$", DoubleToString(absLoss, 2),
            " | RawLots=", DoubleToString(lots, 4));

   // ── Normalize ──
   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lots, minLot);
   lots = MathMin(lots, maxLot);

   // ── Margin check ──
   double freeMargin = m_account.FreeMargin();
   double marginReq = 0;

   if(OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, price, marginReq))
   {
      if(marginReq > freeMargin * 0.9)
      {
         double safeLots = lots * (freeMargin * 0.9) / marginReq;
         safeLots = MathFloor(safeLots / lotStep) * lotStep;
         safeLots = MathMax(safeLots, minLot);

         double actualRisk = safeLots * absLoss;
         Print("⚠ CTR: MARGIN CAP | Wanted ", DoubleToString(lots, 2),
               " lots ($", DoubleToString(riskAmount, 2), " risk)",
               " → Capped to ", DoubleToString(safeLots, 2),
               " lots ($", DoubleToString(actualRisk, 2), " actual risk)");
         lots = safeLots;
      }
   }

   // ── Final margin validation ──
   if(OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, price, marginReq))
   {
      if(marginReq > freeMargin)
      {
         Print("CTR: Cannot afford ", DoubleToString(lots, 2), " lots. No trade.");
         return 0;
      }
   }

   // ── Log actual risk ──
   double actualRisk = lots * absLoss;
   if(DebugMode)
      Print("CTR: Final lots=", DoubleToString(lots, 2),
            " | Actual risk=$", DoubleToString(actualRisk, 2),
            " | Intended=$", DoubleToString(riskAmount, 2),
            " | Accuracy=", DoubleToString(actualRisk / riskAmount * 100, 1), "%");

   return NormalizeDouble(lots, 2);
}

