   double balance    = m_account.Balance();
   double equity     = m_account.Equity();
   double freeMargin = m_account.FreeMargin();
   double riskAmount = balance * RiskPercent / 100.0;
   double tickValue  = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(_Symbol, SYMBOL_TRADE_TICK_SIZE);
   double minLot     = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MIN);
   double maxLot     = SymbolInfoDouble(_Symbol, SYMBOL_VOLUME_MAX);

   if(tickValue <= 0 || tickSize <= 0)
   {
      Print("CTR: tickValue=", tickValue, " tickSize=", tickSize, " — using min lot");
      return minLot;
   }

   // Calculate how much 1 lot loses if price moves SL distance
   double slPrice    = SL_ticks * _Point;
   double lossPerLot = (slPrice / tickSize) * tickValue;

   if(lossPerLot <= 0)
   {
      Print("CTR: lossPerLot=0 — using min lot");
      return minLot;
   }

   double lots = riskAmount / lossPerLot;

   // ── MARGIN CHECK: verify we can afford this lot size ──
   double marginRequired = 0;
   double price = SymbolInfoDouble(_Symbol, SYMBOL_ASK);

   if(!OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, price, marginRequired))
   {
      Print("CTR: OrderCalcMargin failed, trying min lot");
      lots = minLot;
   }
   else if(marginRequired > freeMargin * 0.9)  // use max 90% of free margin
   {
      // Scale down to fit within available margin
      double safeLots = lots * (freeMargin * 0.9) / marginRequired;
      if(DebugMode)
         Print("CTR: Lots reduced for margin | Original=", DoubleToString(lots, 4),
               " | Margin needed=", DoubleToString(marginRequired, 2),
               " | Free margin=", DoubleToString(freeMargin, 2),
               " | Adjusted=", DoubleToString(safeLots, 4));
      lots = safeLots;
   }

   // Final normalize
   lots = NormalizeLots(lots);

   // ── FINAL MARGIN VALIDATION ──
   double finalMargin = 0;
   if(OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, lots, price, finalMargin))
   {
      if(finalMargin > freeMargin)
      {
         Print("CTR: STILL not enough margin after adjustment. Margin=",
               DoubleToString(finalMargin, 2), " Free=", DoubleToString(freeMargin, 2),
               " | Falling back to min lot");
         lots = minLot;

         // Check if even min lot is affordable
         double minMargin = 0;
         if(OrderCalcMargin(ORDER_TYPE_BUY, _Symbol, minLot, price, minMargin))
         {
            if(minMargin > freeMargin)
            {
               Print("CTR: Even min lot (", DoubleToString(minLot, 2),
                     ") requires margin ", DoubleToString(minMargin, 2),
                     " > free ", DoubleToString(freeMargin, 2), " — CANNOT TRADE");
               return 0;
            }
         }
      }
   }

   if(DebugMode)
      Print("CTR: LotCalc | Bal=", DoubleToString(balance, 2),
            " | Free=", DoubleToString(freeMargin, 2),
            " | Risk$=", DoubleToString(riskAmount, 2),
            " | LossPerLot=", DoubleToString(lossPerLot, 2),
            " | Lots=", DoubleToString(lots, 2));

   return lots;
}

